  // 대본을 적절한 길이의 문장 그룹으로 나누는 함수
  // 새로운 장면 분해 형식을 파싱하여 scriptLines로 변환하는 함수
  const parseSceneBlocks = (sceneText: string): Array<{ id: number; text: string }> => {
    if (!sceneText || sceneText.trim().length === 0) {
      return []
    }

    const lines: Array<{ id: number; text: string }> = []
    let currentId = 1

    // 씬 블록을 찾기 위한 정규식
    // 형식: 씬 {number}\n[장면 1]\n(텍스트)\n[장면 2]\n(텍스트)...
    // 플래그 's'는 ES2018 이상이 필요하므로 제거하여 호환성 높임
    const sceneRegex = /씬\s+(\d+)\s*\n\[장면\s+(\d+)\]\s*\n([^[]+?)(?=\[장면\s+\d+\]|씬\s+\d+|$)/g

    let match
    while ((match = sceneRegex.exec(sceneText)) !== null) {
      const sceneNum = match[1]
      const shotNum = match[2]
      const shotText = match[3].trim()

      if (shotText) {
        lines.push({
          id: currentId++,
          text: shotText,
        })
      }
    }

    // 정규식으로 매칭되지 않은 경우, 간단한 파싱 시도
    if (lines.length === 0) {
      // [장면 N] 형식으로 직접 파싱
      const shotRegex = /\[장면\s+\d+\]\s*\n([^\[]+?)(?=\[장면\s+\d+\]|씬\s+\d+|$)/g
      let shotMatch
      while ((shotMatch = shotRegex.exec(sceneText)) !== null) {
        const shotText = shotMatch[1].trim()
        if (shotText) {
          lines.push({
            id: currentId++,
            text: shotText,
          })
        }
      }
    }

    return lines
  }

  // Gemini API를 사용하여 의미 단위 세그먼트 생성
  const generateSemanticSegments = async (text: string, geminiApiKey: string): Promise<string[]> => {
    try {
      // 서버 API 라우트를 통해 호출 (API 키 노출 방지)
      const response = await fetch("/api/gemini/generate-content", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          model: "gemini-2.0-flash-exp",
          contents: [{
            parts: [{
              text: `다음 텍스트를 의미 단위로 분할해주세요. 각 의미 단위는 독립적인 문장이나 구절이어야 합니다. 결과는 JSON 배열 형식으로 반환해주세요.\n\n텍스트: ${text}\n\n결과 형식: ["의미 단위 1", "의미 단위 2", ...]`
            }]
          }],
          generationConfig: {
            temperature: 0.3,
            maxOutputTokens: 2000,
          },
        }),
      })

      if (!response.ok) {
        const errorData = await response.json()
        throw new Error(`Gemini API 호출 실패: ${response.status} - ${errorData.error || errorData.details || "알 수 없는 오류"}`)
      }

      const data = await response.json()
      const resultText = data.candidates?.[0]?.content?.parts?.[0]?.text || ""
      
      // JSON 배열 추출
      const jsonMatch = resultText.match(/\[[\s\S]*\]/)
      if (jsonMatch) {
        const segments = JSON.parse(jsonMatch[0])
        return Array.isArray(segments) ? segments : [text]
      }
      
      // JSON이 없으면 줄바꿈으로 분할
      return resultText.split('\n').filter((s: string) => s.trim().length > 0)
    } catch (error) {
      console.error("[의미 단위 세그먼트 생성 실패]:", error)
      // 실패 시 기본 분할 (문장 단위)
      return text.split(/[.!?。！？]\s*/).filter(s => s.trim().length > 0)
    }
  }

  // AudioBuffer를 WAV Blob으로 변환하는 헬퍼 함수
  const audioBufferToBlob = async (audioBuffer: AudioBuffer): Promise<Blob> => {
    const numberOfChannels = audioBuffer.numberOfChannels
    const sampleRate = audioBuffer.sampleRate
    const length = audioBuffer.length
    
    // 인터리브된 데이터 생성
    const resultBuffer = new Float32Array(length * numberOfChannels)
    let offset = 0
    for (let channel = 0; channel < numberOfChannels; channel++) {
      resultBuffer.set(audioBuffer.getChannelData(channel), offset)
      offset += length
    }
    
    // WAV 인코딩
    const wavBuffer = encodeWAV(resultBuffer, numberOfChannels, sampleRate)
    return new Blob([wavBuffer], { type: 'audio/wav' })
  }

  // Float32Array를 WAV 형식으로 인코딩
  const encodeWAV = (samples: Float32Array, numChannels: number, sampleRate: number): ArrayBuffer => {
    const length = samples.length
    const buffer = new ArrayBuffer(44 + length * 2)
    const view = new DataView(buffer)
    
    // WAV 헤더 작성
    const writeString = (offset: number, string: string) => {
      for (let i = 0; i < string.length; i++) {
        view.setUint8(offset + i, string.charCodeAt(i))
      }
    }
    
    writeString(0, 'RIFF')
    view.setUint32(4, 36 + length * 2, true)
    writeString(8, 'WAVE')
    writeString(12, 'fmt ')
    view.setUint32(16, 16, true)
    view.setUint16(20, 1, true)
    view.setUint16(22, numChannels, true)
    view.setUint32(24, sampleRate, true)
    view.setUint32(28, sampleRate * numChannels * 2, true)
    view.setUint16(32, numChannels * 2, true)
    view.setUint16(34, 16, true)
    writeString(36, 'data')
    view.setUint32(40, length * 2, true)
    
    // 샘플 데이터 변환 (Float32 -> Int16)
    let offset = 44
    for (let i = 0; i < length; i++) {
      const s = Math.max(-1, Math.min(1, samples[i]))
      view.setInt16(offset, s < 0 ? s * 0x8000 : s * 0x7FFF, true)
      offset += 2
    }
    
    return buffer
  }

  // wordTimings를 alignment 형식으로 변환 (Whisper align API 결과를 ElevenLabs 형식으로 변환)
  const convertWordTimingsToAlignment = (
    wordTimings: Array<{ word: string; start: number; end: number; confidence?: number }>,
    text: string
  ): any => {
    if (!wordTimings || wordTimings.length === 0) {
      return null
    }

    // 텍스트를 문자 배열로 변환
    const characters: string[] = []
    const characterStartTimes: number[] = []
    const characterEndTimes: number[] = []

    let textIndex = 0
    for (const wordTiming of wordTimings) {
      const word = wordTiming.word
      const wordStart = wordTiming.start
      const wordEnd = wordTiming.end
      const wordDuration = wordEnd - wordStart

      // 단어의 각 문자에 시간 할당
      for (let i = 0; i < word.length; i++) {
        const char = word[i]
        const charRatio = i / word.length
        const charStart = wordStart + (wordDuration * charRatio)
        const charEnd = i === word.length - 1 
          ? wordEnd 
          : wordStart + (wordDuration * ((i + 1) / word.length))

        characters.push(char)
        characterStartTimes.push(Number.parseFloat(charStart.toFixed(6))) // 소수점 6자리까지
        characterEndTimes.push(Number.parseFloat(charEnd.toFixed(6)))
        textIndex++
      }

      // 단어 뒤에 공백 추가 (마지막 단어가 아니면)
      if (wordTiming !== wordTimings[wordTimings.length - 1]) {
        const spaceStart = wordEnd
        const spaceEnd = wordTiming !== wordTimings[wordTimings.length - 1] 
          ? (wordTimings[wordTimings.indexOf(wordTiming) + 1]?.start || wordEnd)
          : wordEnd

        characters.push(" ")
        characterStartTimes.push(Number.parseFloat(spaceStart.toFixed(6)))
        characterEndTimes.push(Number.parseFloat(Math.min(spaceEnd, wordEnd + 0.1).toFixed(6)))
        textIndex++
      }
    }

    return {
      characters: characters.join(""),
      character_start_times_seconds: characterStartTimes,
      character_end_times_seconds: characterEndTimes,
    }
  }

  // Alignment와 세그먼트를 매칭하여 정확한 자막 타이밍 생성
  const alignmentToPhrases = (
    alignment: any,
    charLimit: number,
    semanticSegments: string[]
  ): Array<{ text: string; start: number; end: number }> => {
    if (!alignment || !alignment.characters || !alignment.character_start_times_seconds || !alignment.character_end_times_seconds) {
      // alignment가 없으면 fallback
      return []
    }

    const characters = alignment.characters
    const startTimes = alignment.character_start_times_seconds
    const endTimes = alignment.character_end_times_seconds

    const phrases: Array<{ text: string; start: number; end: number }> = []
    let currentPhrase = ""
    let phraseStart = 0
    let phraseEnd = 0
    let charIndex = 0

    // semantic segments와 alignment 매칭
    for (const segment of semanticSegments) {
      const segmentStartChar = charIndex
      const segmentEndChar = charIndex + segment.length
      
      // 세그먼트의 시작/종료 문자 인덱스 찾기
      let segmentStartTime = 0
      let segmentEndTime = 0
      
      // 세그먼트의 첫 문자와 마지막 문자의 시간 찾기
      for (let i = 0; i < characters.length; i++) {
        if (i >= segmentStartChar && i < segmentEndChar) {
          if (segmentStartTime === 0 && startTimes[i] !== undefined) {
            segmentStartTime = startTimes[i]
          }
          if (endTimes[i] !== undefined) {
            segmentEndTime = endTimes[i]
          }
        }
      }

      // 세그먼트를 charLimit 단위로 나누기
      let currentLine = ""
      let lineStart = segmentStartTime
      let lineEnd = segmentStartTime

      for (let i = 0; i < segment.length; i++) {
        const char = segment[i]
        const charIdx = segmentStartChar + i
        
        if (charIdx < characters.length) {
          const charStart = startTimes[charIdx] || segmentStartTime
          const charEnd = endTimes[charIdx] || segmentEndTime
          
          const testLine = currentLine + char
          
          if (testLine.length > charLimit && currentLine.length > 0) {
            // 현재 줄 저장
            phrases.push({
              text: currentLine.trim(),
              start: lineStart,
              end: lineEnd,
            })
            // 새 줄 시작
            currentLine = char
            lineStart = charStart
            lineEnd = charEnd
          } else {
            currentLine = testLine
            lineEnd = charEnd
          }
        } else {
          currentLine += char
        }
      }

      // 마지막 줄 저장
      if (currentLine.trim().length > 0) {
        phrases.push({
          text: currentLine.trim(),
          start: lineStart,
          end: segmentEndTime > 0 ? segmentEndTime : lineEnd,
        })
      }

      charIndex = segmentEndChar
    }

    return phrases.length > 0 ? phrases : []
  }

  const splitScriptIntoLines = (scriptText: string, isRefined: boolean = false): Array<{ id: number; text: string }> => {
    if (!scriptText || scriptText.trim().length === 0) {
      return []
    }

    // 정교한 대본의 경우: 의미/장면 단위로 나뉘어 있으므로 줄바꿈을 기준으로 처리
    if (isRefined) {
      // 빈 줄(줄바꿈 2개 이상) 또는 단일 줄바꿈을 기준으로 의미 단위 분리
      const meaningUnits = scriptText.split(/\n\s*\n/).filter(unit => unit.trim().length > 0)
      
      const groupedLines: Array<{ id: number; text: string }> = []
      const TARGET_LINE_LENGTH = 60 // 목표 길이 (10~15초 분량)
      const MIN_LINE_LENGTH = 35 // 최소 길이
      const MAX_LINE_LENGTH = 90 // 최대 길이
      
      for (const unit of meaningUnits) {
        const trimmedUnit = unit.trim().replace(/\n/g, " ") // 단일 줄바꿈은 공백으로 변환
        const unitLength = trimmedUnit.length
        
        // 의미 단위가 이미 적절한 길이면 그대로 사용
        if (unitLength >= MIN_LINE_LENGTH && unitLength <= MAX_LINE_LENGTH) {
          groupedLines.push({
            id: groupedLines.length + 1,
            text: trimmedUnit,
          })
        }
        // 의미 단위가 너무 짧으면 다음 단위와 합치거나 그대로 사용
        else if (unitLength < MIN_LINE_LENGTH) {
          if (groupedLines.length > 0) {
            // 이전 그룹에 합치기
            const lastIndex = groupedLines.length - 1
            const combined = groupedLines[lastIndex].text + " " + trimmedUnit
            if (combined.length <= MAX_LINE_LENGTH) {
              groupedLines[lastIndex] = {
                ...groupedLines[lastIndex],
                text: combined,
              }
            } else {
              // 합치면 너무 길면 별도로 추가
              groupedLines.push({
                id: groupedLines.length + 1,
                text: trimmedUnit,
              })
            }
          } else {
            // 첫 번째 그룹이면 그대로 추가
            groupedLines.push({
              id: groupedLines.length + 1,
              text: trimmedUnit,
            })
          }
        }
        // 의미 단위가 너무 길면 문장 단위로 나누기
        else {
          // 문장 부호로 나누기
          const sentences = trimmedUnit.split(/([.!?。！？]\s*)/).filter(s => s.trim().length > 0)
          let currentGroup = ""
          
          for (let i = 0; i < sentences.length; i++) {
            const sentence = sentences[i].trim()
            if (!sentence) continue
            
            const potentialLength = currentGroup ? (currentGroup + " " + sentence).length : sentence.length
            
            if (potentialLength > MAX_LINE_LENGTH && currentGroup) {
              groupedLines.push({
                id: groupedLines.length + 1,
                text: currentGroup,
              })
              currentGroup = sentence
            } else if (potentialLength >= TARGET_LINE_LENGTH && potentialLength <= MAX_LINE_LENGTH) {
              const finalText = currentGroup ? currentGroup + " " + sentence : sentence
              groupedLines.push({
                id: groupedLines.length + 1,
                text: finalText,
              })
              currentGroup = ""
            } else {
              currentGroup = currentGroup ? currentGroup + " " + sentence : sentence
            }
          }
          
          if (currentGroup) {
            if (groupedLines.length > 0 && currentGroup.length < MIN_LINE_LENGTH) {
              const lastIndex = groupedLines.length - 1
              groupedLines[lastIndex] = {
                ...groupedLines[lastIndex],
                text: groupedLines[lastIndex].text + " " + currentGroup,
              }
            } else {
              groupedLines.push({
                id: groupedLines.length + 1,
                text: currentGroup,
              })
            }
          }
        }
      }
      
      return groupedLines.map((l, index) => {
        let text = l.text.trim()
        if (text.length > 0 && !/[.!?。！？]$/.test(text)) {
          text = text + "."
        }
        return { ...l, id: index + 1, text }
      })
    }

    // 기본 대본의 경우: 기존 로직 사용 (문장 부호 기준 + 길이 기반 그룹화)
    // 문장 부호를 보존하면서 문장 단위로 나누기
    const sentences: string[] = []
    const sentenceEndRegex = /([.!?。！？])\s*/g
    let lastIndex = 0
    let match
    
    while ((match = sentenceEndRegex.exec(scriptText)) !== null) {
      const sentence = scriptText.substring(lastIndex, match.index + match[0].length).trim()
      if (sentence.length > 0) {
        sentences.push(sentence)
      }
      lastIndex = sentenceEndRegex.lastIndex
    }
    
    // 마지막 부분 처리
    if (lastIndex < scriptText.length) {
      const lastSentence = scriptText.substring(lastIndex).trim()
      if (lastSentence.length > 0) {
        sentences.push(lastSentence)
      }
    }

    if (sentences.length === 0) {
      return []
    }

    const groupedLines: Array<{ id: number; text: string }> = []
    // TTS 속도: 분당 약 200-250자 기준
    // 10초 = 약 33~42자, 15초 = 약 50~63자
    const TARGET_LINE_LENGTH = 60 // 목표 길이 (10~15초 분량, 약 50~60자)
    const MIN_LINE_LENGTH = 35 // 최소 길이 (약 10초 분량)
    const MAX_LINE_LENGTH = 90 // 최대 길이 (약 15초 분량)
    
    let currentGroup: string[] = []
    let currentLength = 0
    
    for (let i = 0; i < sentences.length; i++) {
      const sentence = sentences[i]
      const sentenceLength = sentence.length
      const potentialLength = currentLength + (currentLength > 0 ? 1 : 0) + sentenceLength // 공백 포함
      
      // 현재 그룹이 비어있으면 추가
      if (currentGroup.length === 0) {
        currentGroup.push(sentence)
        currentLength = sentenceLength
        // 한 문장이 이미 최대 길이를 넘으면 바로 저장
        if (sentenceLength > MAX_LINE_LENGTH) {
          groupedLines.push({
            id: groupedLines.length + 1,
            text: sentence,
          })
          currentGroup = []
          currentLength = 0
        }
        continue
      }
      
      // 현재 그룹에 추가했을 때 최대 길이를 넘으면 현재 그룹 저장하고 새로 시작
      if (potentialLength > MAX_LINE_LENGTH) {
        if (currentGroup.length > 0) {
          const groupText = currentGroup.join(" ")
          groupedLines.push({
            id: groupedLines.length + 1,
            text: groupText,
          })
        }
        currentGroup = [sentence]
        currentLength = sentenceLength
        // 한 문장이 이미 최대 길이를 넘으면 바로 저장
        if (sentenceLength > MAX_LINE_LENGTH) {
          groupedLines.push({
            id: groupedLines.length + 1,
            text: sentence,
          })
          currentGroup = []
          currentLength = 0
        }
        continue
      }
      
      // 목표 길이에 도달하면 (목표 길이 이상이고 최대 길이 미만) 그룹 저장
      if (potentialLength >= TARGET_LINE_LENGTH && potentialLength <= MAX_LINE_LENGTH) {
        currentGroup.push(sentence)
        const groupText = currentGroup.join(" ")
        groupedLines.push({
          id: groupedLines.length + 1,
          text: groupText,
        })
        currentGroup = []
        currentLength = 0
        continue
      }
      
      // 목표 길이보다 작으면 계속 추가
      if (potentialLength < TARGET_LINE_LENGTH) {
        currentGroup.push(sentence)
        currentLength = potentialLength
        continue
      }
    }
    
    // 남은 문장들 처리
    if (currentGroup.length > 0) {
      const remainingText = currentGroup.join(" ")
      // 최소 길이를 만족하거나 마지막 그룹이면 저장
      if (remainingText.length >= MIN_LINE_LENGTH || groupedLines.length === 0) {
        groupedLines.push({
          id: groupedLines.length + 1,
          text: remainingText,
        })
      } else if (groupedLines.length > 0) {
        // 최소 길이 미만이면 마지막 그룹에 합치기
        const lastIndex = groupedLines.length - 1
        groupedLines[lastIndex] = {
          ...groupedLines[lastIndex],
          text: groupedLines[lastIndex].text + " " + remainingText,
        }
      }
    }
    
    // ID 재정렬 및 마침표 추가
    return groupedLines.map((l, index) => {
      let text = l.text.trim()
      // 문장 끝에 마침표가 없으면 추가
      if (text.length > 0 && !/[.!?。！？]$/.test(text)) {
        text = text + "."
      }
      return { ...l, id: index + 1, text }
    })
  }

  const handleBasicScriptGeneration = async () => {
    if (!scriptPlan) {
      alert("대본 기획안을 먼저 생성해주세요.")
      return
    }

    setIsGenerating(true)
    try {
      console.log("[v0] 기본 대본 생성 시작")
      const topic = isCustomTopicSelected ? customTopic : selectedTopic
      // 선택한 시간에 맞춰 대본 길이 계산 (1초당 6.9자 - 목표 글자수 계산)
      const targetChars = Math.floor(scriptDuration * 60 * 6.9)
      // folktale 카테고리 또는 Type D 선택 시 자동으로 스토리 모드로 설정
      const shouldUseStoryMode = isStoryMode || selectedCategory === "folktale" || selectedContentType === "D"
      const fullScript = await generateFinalScript(scriptPlan, topic || "", getApiKey(), scriptDuration, targetChars, selectedCategory, shouldUseStoryMode)
      
      // 대본 마지막에 CTA 추가
      const ctaText = "\n\n이 영상이 도움이 되셨다면 좋아요와 구독 부탁드립니다. 여러분의 응원이 제게 큰 힘이 됩니다. 다음 영상에서도 더 유용한 정보를 공유하겠습니다. 감사합니다."
      const scriptWithCTA = fullScript.trim() + ctaText
      
      setScript(scriptWithCTA)
      
      // 대본을 문장 단위로 분리하고 적절한 길이로 묶기
      const groupedLines = splitScriptIntoLines(fullScript)
      
      setScriptLines(groupedLines)
      setCompletedSteps((prev) => [...prev, "script"])
      console.log("[v0] 기본 대본 생성 완료, 문장 그룹 수:", groupedLines.length)
    } catch (error) {
      console.error("기본 대본 생성 실패:", error)
      const errorMessage = error instanceof Error ? error.message : "알 수 없는 오류가 발생했습니다."
      alert(`기본 대본 생성에 실패했습니다: ${errorMessage}`)
    } finally {
      setIsGenerating(false)
    }
  }

  const handleRefinedScriptGeneration = async () => {
    if (!scriptPlan) {
      alert("대본 기획안을 먼저 생성해주세요.")
      return
    }

    setIsGenerating(true)
    const startTime = Date.now()
    
    // folktale 카테고리 또는 Type D 선택 시 자동으로 스토리 모드로 설정
    const shouldUseStoryMode = isStoryMode || selectedCategory === "folktale" || selectedContentType === "D"
    
    // 목표 글자수 기반 예상 시간 계산 (1000자당 약 10-15초 소요 가정)
    const topic = isCustomTopicSelected ? customTopic : selectedTopic
    // 목표 글자수 계산: 기본 계산 + 여유분 500자 (AI가 더 많이 작성하도록 유도)
    const baseTargetChars = Math.floor(scriptDuration * 60 * 6.9) // 1초당 6.9자
    const targetChars = baseTargetChars + 500 // 여유분 500자 추가
    const estimatedSeconds = Math.max(30, Math.ceil(targetChars / 1000 * 12)) // 최소 30초, 1000자당 12초
    const estimatedTime = estimatedSeconds * 1000 // 밀리초로 변환
    
    // 진행률 업데이트 인터벌 시작 (분할이 없는 경우에만 시간 기반 진행률 표시)
    const progressInterval = setInterval(() => {
      const elapsedTime = Date.now() - startTime
      // 분할이 없는 경우에만 시간 기반 진행률 계산
      const shouldSplit = scriptDuration && scriptDuration >= 10
      if (!shouldSplit) {
        // 분할이 없는 경우: 시간 기반 진행률
      const progress = Math.min(95, Math.floor((elapsedTime / estimatedTime) * 100))
      setScriptGenerationProgress({
        progress,
        elapsedTime: Math.floor(elapsedTime / 1000), // 초 단위
        estimatedTime: Math.floor(estimatedTime / 1000) // 초 단위
      })
      }
      // 분할이 있는 경우는 분할별로 진행률이 업데이트되므로 인터벌에서는 업데이트하지 않음
    }, 500) // 0.5초마다 업데이트
    
    try {
      console.log("[v0] 정교한 대본 생성 시작")
      const geminiApiKey = getGeminiApiKey()
      if (!geminiApiKey) {
        clearInterval(progressInterval)
        setScriptGenerationProgress(null)
        alert("Gemini API 키를 설정해주세요. 설정 페이지에서 API 키를 입력하고 저장해주세요.")
        return
      }
      // folktale 카테고리 또는 Type D 선택 시 자동으로 스토리 모드로 설정
      const shouldUseStoryMode = isStoryMode || selectedCategory === "folktale" || selectedContentType === "D"
      
      // 분할 수 계산 (10분 이상일 때만 분할)
      const shouldSplit = scriptDuration && scriptDuration >= 10
      let totalParts = 1
      if (scriptDuration === 10) totalParts = 2
      else if (scriptDuration === 15) totalParts = 3
      else if (scriptDuration === 20) totalParts = 4
      else if (scriptDuration === 25) totalParts = 5
      else if (scriptDuration === 30) totalParts = 6
      else if (scriptDuration === 35) totalParts = 7
      else if (scriptDuration === 40) totalParts = 8

      let fullScript = ""

      if (!shouldSplit) {
        // 5분: 한 번에 생성
        const response = await fetch("/api/generate-refined-script", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
        scriptPlan, 
            topic: topic || "",
            duration: scriptDuration,
        targetChars, 
            isStoryMode: shouldUseStoryMode,
            apiKey: geminiApiKey
          })
        })

        if (!response.ok) {
          let errorData
          try {
            errorData = await response.json()
          } catch (e) {
            if (response.status === 504 || response.status === 408) {
              throw new Error("대본 생성 시간이 너무 오래 걸립니다. Vercel의 타임아웃 제한(5분)을 초과했습니다.")
            }
            throw new Error(`대본 생성 실패: ${response.status}`)
          }
          throw new Error(errorData.error || `대본 생성 실패: ${response.status}`)
        }

        const result = await response.json()
        if (!result || !result.script) {
          throw new Error("대본 생성 응답이 올바르지 않습니다.")
        }
        fullScript = result.script
      } else {
        // 10분 이상: 각 분할을 순차적으로 호출
        const parts: string[] = []
        
        for (let partNumber = 1; partNumber <= totalParts; partNumber++) {
          // 진행률 업데이트 (분할 기반)
          const progress = Math.floor(((partNumber - 1) / totalParts) * 100)
          setScriptGenerationProgress({
            progress,
            elapsedTime: Math.floor((Date.now() - startTime) / 1000),
            estimatedTime: Math.floor(estimatedTime / 1000),
            currentPart: partNumber,
            totalParts
          })

          console.log(`[v0] ${partNumber}/${totalParts} 분할 생성 시작`)
          
          // 타임아웃 시 자동 재시도 로직
          const maxRetries = 3
          let partScript: string | null = null
          let lastError: Error | null = null
          
          for (let retryAttempt = 0; retryAttempt < maxRetries; retryAttempt++) {
            try {
              if (retryAttempt > 0) {
                const retryDelay = 2000 * retryAttempt // 2초, 4초, 6초
                console.log(`[v0] ${partNumber}회차 재시도 ${retryAttempt}/${maxRetries - 1} - ${retryDelay}ms 후 재시도...`)
                await new Promise((resolve) => setTimeout(resolve, retryDelay))
              }
              
              const response = await fetch("/api/generate-refined-script-part", {
                method: "POST",
                headers: {
                  "Content-Type": "application/json",
                },
                body: JSON.stringify({
                  scriptPlan,
                  topic: topic || "",
                  duration: scriptDuration,
                  partNumber,
                  totalParts,
                  targetChars,
                  previousParts: parts.join("\n\n"),
                  isStoryMode: shouldUseStoryMode,
                  apiKey: geminiApiKey
                })
              })

              if (!response.ok) {
                let errorData
                try {
                  errorData = await response.json()
                } catch (e) {
                  // JSON 파싱 실패 시 (타임아웃 등)
                  if (response.status === 504 || response.status === 408) {
                    if (retryAttempt < maxRetries - 1) {
                      console.warn(`[v0] ${partNumber}회차 타임아웃 발생, 재시도 중... (${retryAttempt + 1}/${maxRetries})`)
                      lastError = new Error(`타임아웃 (재시도 ${retryAttempt + 1}/${maxRetries})`)
                      continue
                    }
                    throw new Error(`${partNumber}회차 생성 시간이 너무 오래 걸립니다. 타임아웃이 발생했습니다.`)
                  }
                  throw new Error(`${partNumber}회차 생성 실패: ${response.status}`)
                }
                
                // 타임아웃 오류인 경우 재시도
                if (response.status === 504 || response.status === 408) {
                  if (retryAttempt < maxRetries - 1) {
                    console.warn(`[v0] ${partNumber}회차 타임아웃 발생, 재시도 중... (${retryAttempt + 1}/${maxRetries})`)
                    lastError = new Error(`타임아웃: ${errorData.error || '서버 응답 시간 초과'} (재시도 ${retryAttempt + 1}/${maxRetries})`)
                    continue
                  }
                  throw new Error(`${partNumber}회차 생성 시간이 너무 오래 걸립니다. 타임아웃이 발생했습니다.`)
                }
                
                // 다른 오류는 재시도하지 않고 바로 throw
                throw new Error(errorData.error || `${partNumber}회차 생성 실패: ${response.status}`)
              }

              const result = await response.json()
              if (!result || !result.script) {
                if (retryAttempt < maxRetries - 1) {
                  console.warn(`[v0] ${partNumber}회차 응답이 올바르지 않음, 재시도 중... (${retryAttempt + 1}/${maxRetries})`)
                  lastError = new Error(`${partNumber}회차 생성 응답이 올바르지 않습니다.`)
                  continue
                }
                throw new Error(`${partNumber}회차 생성 응답이 올바르지 않습니다.`)
              }

              // 성공
              partScript = result.script
              console.log(`[v0] ${partNumber}/${totalParts} 분할 생성 완료: ${result.script.length}자`)
              break // 성공 시 루프 탈출
              
            } catch (error) {
              lastError = error instanceof Error ? error : new Error(String(error))
              
              // 타임아웃 관련 오류가 아니면 재시도하지 않음
              const errorMessage = lastError.message
              if (!errorMessage.includes("타임아웃") && !errorMessage.includes("504") && !errorMessage.includes("408") && !errorMessage.includes("timeout")) {
                throw lastError
              }
              
              // 타임아웃 오류이고 재시도 가능한 경우
              if (retryAttempt < maxRetries - 1) {
                console.warn(`[v0] ${partNumber}회차 오류 발생, 재시도 중... (${retryAttempt + 1}/${maxRetries}):`, errorMessage)
                continue
              }
              
              // 모든 재시도 실패
              throw lastError
            }
          }
          
          // 재시도 후에도 실패한 경우
          if (!partScript) {
            throw lastError || new Error(`${partNumber}회차 생성에 실패했습니다.`)
          }
          
          parts.push(partScript)
          
          // 분할 완료 후 진행률 업데이트
          const completedProgress = Math.floor((partNumber / totalParts) * 100)
          setScriptGenerationProgress({
            progress: completedProgress,
            elapsedTime: Math.floor((Date.now() - startTime) / 1000),
            estimatedTime: Math.floor(estimatedTime / 1000),
            currentPart: partNumber,
            totalParts
          })
        }

        // 모든 분할 합치기
        fullScript = parts.join("\n\n")
        
        // 최종 진행률 100%로 업데이트
        setScriptGenerationProgress({
          progress: 100,
          elapsedTime: Math.floor((Date.now() - startTime) / 1000),
          estimatedTime: Math.floor(estimatedTime / 1000),
          currentPart: totalParts,
          totalParts
        })
      }
      
      // 대본이 비어있는지 확인
      if (!fullScript || typeof fullScript !== 'string' || fullScript.trim().length === 0) {
        throw new Error("생성된 대본이 비어있습니다. 다시 시도해주세요.")
      }
      
      // 대본 마지막에 CTA 추가 (이미 CTA가 있으면 추가하지 않음)
      const ctaText = "\n\n이 영상이 도움이 되셨다면 좋아요와 구독 부탁드립니다. 여러분의 응원이 제게 큰 힘이 됩니다. 다음 영상에서도 더 유용한 정보를 공유하겠습니다. 감사합니다."
      // CTA 중복 체크: 대본 끝부분에 이미 CTA가 있는지 확인
      const scriptEnd = fullScript.trim().slice(-200) // 마지막 200자만 확인
      const hasCTA = scriptEnd.includes("좋아요와 구독") || (scriptEnd.includes("좋아요") && scriptEnd.includes("구독")) || scriptEnd.includes("구독 부탁드립니다")
      const scriptWithCTA = hasCTA ? fullScript : fullScript.trim() + ctaText
      
      setScript(scriptWithCTA)
      
      // 정교한 대본은 의미/장면 기반으로 나누기
      const groupedLines = splitScriptIntoLines(scriptWithCTA, true)
      
      setScriptLines(groupedLines)
      setCompletedSteps((prev) => [...prev, "script"])
      console.log("[v0] 정교한 대본 생성 완료, 문장 그룹 수:", groupedLines.length)
      playNotificationSound() // 알림음 재생
      
      // 완료 시 100% 표시
      setScriptGenerationProgress({
        progress: 100,
        elapsedTime: Math.floor((Date.now() - startTime) / 1000),
        estimatedTime: Math.floor(estimatedTime / 1000)
      })
    } catch (error) {
      console.error("정교한 대본 생성 실패:", error)
      
      // 오류 메시지 추출 및 개선
      let errorMessage = "알 수 없는 오류가 발생했습니다."
      
      if (error instanceof Error) {
        errorMessage = error.message
        
        // Next.js Server Components 오류인 경우 더 친절한 메시지 제공
        if (errorMessage.includes("Server Components render") || errorMessage.includes("digest")) {
          errorMessage = "서버에서 대본 생성 중 오류가 발생했습니다. 가능한 원인:\n\n" +
            "1. Gemini API 호출 실패 (API 키 확인 필요)\n" +
            "2. 네트워크 연결 문제\n" +
            "3. 서버 타임아웃 (생성 시간이 너무 길어짐)\n" +
            "4. 메모리 부족\n\n" +
            "개발자 도구 콘솔에서 자세한 오류 정보를 확인하세요."
        }
        
        // 구체적인 오류 메시지가 있는 경우 그대로 사용
        if (errorMessage.includes("API 키") || errorMessage.includes("SAFETY") || errorMessage.includes("RECITATION")) {
          // 이미 구체적인 메시지가 있음
        }
      }
      
      // 오류 상세 정보를 콘솔에 출력 (디버깅용)
      if (error instanceof Error && error.stack) {
        console.error("오류 스택 트레이스:", error.stack)
      }
      
      alert(`정교한 대본 생성에 실패했습니다: ${errorMessage}\n\n한번더 생성해주세요.`)
    } finally {
      clearInterval(progressInterval)
      setIsGenerating(false)
      // 완료 후 1초 뒤 진행률 초기화
      setTimeout(() => {
        setScriptGenerationProgress(null)
      }, 1000)
    }
  }

  const handleDirectScriptSubmit = () => {
    if (!directScript.trim()) return

    setScript(directScript)
    
    // 대본을 문장 단위로 분리하고 적절한 길이로 묶기
    const groupedLines = splitScriptIntoLines(directScript)
    
    setScriptLines(groupedLines)
    setCompletedSteps((prev) => [...prev, "script"])
    setShowDirectScriptInput(false)
    console.log("[v0] 직접 입력된 대본 적용 완료, 문장 그룹 수:", groupedLines.length)
  }

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text)
  }

  // 커스텀 이미지 생성 (한글 프롬프트 입력)
  const handleGenerateCustomImage = async (lineId: number) => {
    if (!customImagePrompt.trim()) {
      alert("이미지 설명을 입력해주세요.")
      return
    }

    const openaiApiKey = getApiKey("openai_api_key")
    const replicateApiKey = getApiKey("replicate_api_key")

    if (!openaiApiKey) {
      alert("OpenAI API 키가 필요합니다. 설정에서 API 키를 입력해주세요.")
      return
    }

    if (!replicateApiKey) {
      alert("Replicate API 키가 필요합니다. 설정에서 API 키를 입력해주세요.")
      return
    }

    setIsGeneratingCustomImage(true)
    
    // 이미지 생성 시작 시 해당 이미지의 영상 데이터 초기화
    setConvertedVideos((prev) => {
      const newMap = new Map(prev)
      newMap.delete(lineId)
      return newMap
    })
    
    try {
      // 한글 프롬프트를 영어로 변환
      console.log(`[v0] 커스텀 이미지 생성 시작 (줄 ${lineId}):`, customImagePrompt)
      
      // generateCustomPrompt 함수 사용
      const { generateCustomPrompt } = await import("./actions")
      let englishPrompt = await generateCustomPrompt(customImagePrompt, openaiApiKey)
      
      // 카테고리별 프롬프트 추가 (16:9 비율 강제)
      // 모든 카테고리에서 스타일 적용
      if (imageStyle) {
        englishPrompt = await generateImagePrompt(customImagePrompt, openaiApiKey, selectedCategory || "health", imageStyle)
      } else {
        // 다른 카테고리는 기본 프롬프트에 16:9 강제 추가
        if (!englishPrompt.toLowerCase().includes("16:9") && !englishPrompt.toLowerCase().includes("aspect ratio")) {
          englishPrompt = `${englishPrompt}, 16:9 aspect ratio, cinematic composition`
        }
      }
      
      console.log(`[v0] 변환된 영어 프롬프트:`, englishPrompt)

      // 이미지 생성
      const response = await fetch("/api/generate-image", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          scriptText: customImagePrompt,
          openaiApiKey,
          replicateApiKey,
          category: selectedCategory || "health",
          historyStyle: imageStyle,
          customPrompt: englishPrompt, // 직접 프롬프트 전달
        }),
      })

      if (!response.ok) {
        const errorData = await response.json()
        throw new Error(errorData.error || "이미지 생성 실패")
      }

      const data = await response.json()
      console.log(`[v0] 커스텀 이미지 생성 완료:`, data.imageUrl)

      // 생성된 이미지 업데이트
      setGeneratedImages((prev) => {
        const filtered = prev.filter((img) => img.lineId !== lineId)
        return [
          ...filtered,
          {
            lineId: lineId,
            imageUrl: data.imageUrl,
            prompt: englishPrompt,
            createdAt: Date.now(), // 이미지 생성 시간 저장
          },
        ]
      })

      setCustomImageDialogOpen(null)
      setCustomImagePrompt("")
      // alert("이미지가 생성되었습니다!") // 완료 알림 제거
    } catch (error) {
      console.error(`[v0] 커스텀 이미지 생성 실패 (줄 ${lineId}):`, error)
      alert(`이미지 생성에 실패했습니다: ${error instanceof Error ? error.message : "알 수 없는 오류"}`)
    } finally {
      setIsGeneratingCustomImage(false)
    }
  }

  // 이미지/영상 업로드 핸들러
  const handleImageUpload = async (lineId: number, file: File) => {
    try {
      // 동영상 파일 차단
      if (file.type.startsWith("video/")) {
        alert("동영상 파일은 업로드할 수 없습니다. 이미지 파일만 업로드 가능합니다.")
        return
      }
      
      // 이미지 파일만 처리
      // 16:9 비율로 이미지 리사이즈
      const resizedImage = await resizeImageTo16_9(file)
      
      // Base64로 변환
      const reader = new FileReader()
      reader.onloadend = () => {
        const base64 = reader.result as string
        const imageUrl = base64

        // 업로드된 이미지 업데이트
        setGeneratedImages((prev) => {
          const filtered = prev.filter((img) => img.lineId !== lineId)
          return [
            ...filtered,
            {
              lineId: lineId,
              imageUrl: imageUrl,
              prompt: "사용자 업로드 이미지",
            },
          ]
        })
        
        // 이미지로 교체했으므로 변환된 영상 제거
        setConvertedVideos((prev) => {
          const newMap = new Map(prev)
          newMap.delete(lineId)
          return newMap
        })

        // 이미지 변경 시 videoData 초기화 (미리보기 재생성 필요)
        setVideoData(null)
        setAutoImages([])
        
        // alert("이미지가 업로드되었습니다!") // 완료 알림 제거
      }
      reader.readAsDataURL(resizedImage)
    } catch (error) {
      console.error(`[v0] 파일 업로드 실패 (줄 ${lineId}):`, error)
      alert(`파일 업로드에 실패했습니다: ${error instanceof Error ? error.message : "알 수 없는 오류"}`)
    }
  }

  // Scene 이미지 업로드 핸들러 (동영상 업로드 불가)
  const handleSceneImageUpload = async (sceneNumber: number, imageNumber: number, file: File) => {
    try {
      // 동영상 파일 차단
      if (file.type.startsWith("video/")) {
        alert("동영상 파일은 업로드할 수 없습니다. 이미지 파일만 업로드 가능합니다.")
        return
      }
      
      // 이미지 파일만 처리
      // 16:9 비율로 이미지 리사이즈
      const resizedImage = await resizeImageTo16_9(file)
      
      // Base64로 변환
      const reader = new FileReader()
      reader.onloadend = () => {
        const base64 = reader.result as string
        const imageUrl = base64

        // 업로드된 이미지 업데이트
        setSceneImagePrompts((prev) => {
          return prev.map((scene) => {
            if (scene.sceneNumber === sceneNumber) {
              return {
                ...scene,
                images: scene.images.map((img) => {
                  if (img.imageNumber === imageNumber) {
                    return {
                      ...img,
                      imageUrl: imageUrl,
                    }
                  }
                  return img
                }),
              }
            }
            return scene
          })
        })
        
        // 이미지로 교체했으므로 변환된 영상 제거
        setConvertedSceneVideos((prev) => {
          const newMap = new Map(prev)
          newMap.delete(`${sceneNumber}-${imageNumber}`)
          return newMap
        })

        // 이미지 변경 시 videoData 초기화 (미리보기 재생성 필요)
        setVideoData(null)
        setAutoImages([])
        
        // alert("이미지가 업로드되었습니다!") // 완료 알림 제거
      }
      reader.readAsDataURL(resizedImage)
    } catch (error) {
      console.error(`[Scene] 파일 업로드 실패 (Scene ${sceneNumber}, Image ${imageNumber}):`, error)
      alert(`파일 업로드에 실패했습니다: ${error instanceof Error ? error.message : "알 수 없는 오류"}`)
    }
  }

  // 이미지를 16:9 비율로 리사이즈하는 함수
  const resizeImageTo16_9 = (file: File): Promise<File> => {
    return new Promise((resolve, reject) => {
      const img = new Image()
      img.onload = () => {
        const canvas = document.createElement("canvas")
        const ctx = canvas.getContext("2d")
        if (!ctx) {
          reject(new Error("Canvas context를 가져올 수 없습니다."))
          return
        }

        // 16:9 비율 계산
        const targetAspect = 16 / 9
        const imgAspect = img.width / img.height

        let drawWidth = img.width
        let drawHeight = img.height
        let x = 0
        let y = 0

        if (imgAspect > targetAspect) {
          // 이미지가 더 넓음 - 높이 기준으로 크롭
          drawHeight = img.height
          drawWidth = img.height * targetAspect
          x = (img.width - drawWidth) / 2
        } else {
          // 이미지가 더 높음 - 너비 기준으로 크롭
          drawWidth = img.width
          drawHeight = img.width / targetAspect
          y = (img.height - drawHeight) / 2
        }

        canvas.width = 1920 // 고해상도
        canvas.height = 1080

        ctx.drawImage(img, x, y, drawWidth, drawHeight, 0, 0, canvas.width, canvas.height)

        canvas.toBlob((blob) => {
          if (!blob) {
            reject(new Error("이미지 변환에 실패했습니다."))
            return
          }
          const resizedFile = new File([blob], file.name, { type: "image/jpeg" })
          resolve(resizedFile)
        }, "image/jpeg", 0.9)
      }
      img.onerror = () => reject(new Error("이미지 로드에 실패했습니다."))
      img.src = URL.createObjectURL(file)
    })
  }

  // Scene 이미지를 영상으로 변환하는 핸들러
  const handleConvertSceneImageToVideo = async (sceneNumber: number, imageNumber: number, imageUrl: string) => {
    const videoKey = `${sceneNumber}-${imageNumber}`
    
    if (isConvertingSceneVideo.has(videoKey)) {
      return
    }

    setIsConvertingSceneVideo((prev) => new Set(prev).add(videoKey))
    
    const replicateApiKey = typeof window !== "undefined" ? localStorage.getItem("replicate_api_key") || undefined : undefined

    if (!replicateApiKey) {
      alert("Replicate API 키가 필요합니다. 설정에서 API 키를 입력해주세요.")
      setIsConvertingSceneVideo((prev) => {
        const newSet = new Set(prev)
        newSet.delete(videoKey)
        return newSet
      })
      return
    }

    try {
      const { convertImageToVideo } = await import("./actions")
      const videoUrl = await convertImageToVideo(imageUrl, replicateApiKey)
      
      if (videoUrl) {
        setConvertedSceneVideos((prev) => {
          const newMap = new Map(prev)
          newMap.set(videoKey, videoUrl)
          return newMap
        })
        console.log(`[Scene Video] 이미지-투-비디오 변환 완료 (Scene ${sceneNumber}, Image ${imageNumber}):`, videoUrl)
      }
    } catch (error) {
      console.error(`[Scene Video] 이미지-투-비디오 변환 실패 (Scene ${sceneNumber}, Image ${imageNumber}):`, error)
      alert(`영상 변환에 실패했습니다: ${error instanceof Error ? error.message : "알 수 없는 오류"}`)
    } finally {
      setIsConvertingSceneVideo((prev) => {
        const newSet = new Set(prev)
        newSet.delete(videoKey)
        return newSet
      })
    }
  }

  // 선택한 이미지를 영상으로 변환하는 핸들러
  const handleConvertImagesToVideo = async () => {
    if (selectedImagesForVideo.size === 0) {
      alert("영상으로 변환할 이미지를 선택해주세요.")
      return
    }

    setIsConvertingToVideo(true)
    // 로컬스토리지에서 직접 가져오기 (다른 부분과 동일한 방식)
    const replicateApiKey = typeof window !== "undefined" ? localStorage.getItem("replicate_api_key") || undefined : undefined

    if (!replicateApiKey) {
      alert("Replicate API 키가 필요합니다. 설정에서 API 키를 입력해주세요.")
      setIsConvertingToVideo(false)
      return
    }

    try {
      const selectedImageIds = Array.from(selectedImagesForVideo)
      let successCount = 0

      for (const imageId of selectedImageIds) {
        const image = generatedImages.find((img) => img.lineId === imageId)
        if (!image) continue

        try {
          console.log(`[Video] 이미지-투-비디오 변환 시작 (문장 ${imageId}):`, image.imageUrl)
          
          // 서버 액션 호출
          const { convertImageToVideo } = await import("./actions")
          const videoUrl = await convertImageToVideo(image.imageUrl, replicateApiKey)
          
          if (videoUrl) {
            setConvertedVideos((prev) => {
              const newMap = new Map(prev)
              newMap.set(imageId, videoUrl)
              return newMap
            })
            successCount++
            console.log(`[Video] 이미지-투-비디오 변환 완료 (문장 ${imageId}):`, videoUrl)
          }
        } catch (error) {
          console.error(`[Video] 이미지-투-비디오 변환 실패 (문장 ${imageId}):`, error)
          // 실패해도 계속 진행
        }
      }

      if (successCount > 0) {
        alert(`${successCount}개의 이미지가 영상으로 변환되었습니다!`)
        // 선택 해제
        setSelectedImagesForVideo(new Set())
      } else {
        alert("영상 변환에 실패했습니다. 다시 시도해주세요.")
      }
    } catch (error) {
      console.error("[Video] 영상 변환 실패:", error)
      alert("영상 변환 중 오류가 발생했습니다.")
    } finally {
      setIsConvertingToVideo(false)
    }
  }

  // 새로운 이미지 생성 핸들러 (문장 리스트 기반)
  const handleGenerateImagesForLines = async () => {
    if (scriptLines.length === 0) {
      alert("생성된 문장 리스트가 없습니다. 먼저 대본을 생성해주세요.")
      return
    }

    const openaiApiKey = getApiKey("openai_api_key")
    const replicateApiKey = getApiKey("replicate_api_key")

    if (!openaiApiKey) {
      alert("OpenAI API 키가 필요합니다. 설정에서 API 키를 입력해주세요.")
      if (isAutoMode) {
        setIsAutoMode(false)
        setAutoModeStep("")
      }
      return
    }

    if (!replicateApiKey) {
      alert("Replicate API 키가 필요합니다. 설정에서 API 키를 입력해주세요.")
      if (isAutoMode) {
        setIsAutoMode(false)
        setAutoModeStep("")
      }
      return
    }

    setIsGeneratingImages(true)
    if (isAutoMode) {
      setAutoModeStep("이미지 생성 중...")
      setAutoModeProgress({ current: "4/7", total: 7 })
    }
    setImageGenerationProgress({ current: 0, total: scriptLines.length })
    // 기존 이미지 초기화
    setGeneratedImages([])
    // 변환된 영상 데이터 초기화 (영상 제거)
    setConvertedVideos(new Map())

    let successCount = 0
    let commonStylePrompt: string | undefined = undefined

    try {
      // 1. 전체 대본의 공통 스타일 프롬프트 생성 (첫 번째 이미지 생성 전)
      const topic = isCustomTopicSelected ? customTopic : selectedTopic
      if (topic) {
        try {
          // commonStylePrompt = await generateCommonStylePrompt(
          //   topic,
          //   selectedCategory || "health",
          //   openaiApiKey,
          //   imageStyle
          // )
          // 임시로 주석 처리 (import 에러 해결 후 활성화)
          commonStylePrompt = undefined
          // console.log("[v0] 공통 스타일 프롬프트 생성 완료:", commonStylePrompt)
        } catch (error) {
          console.warn("[v0] 공통 스타일 프롬프트 생성 실패, 계속 진행:", error)
          // 공통 스타일 생성 실패해도 계속 진행
        }
      }

      // 2. 각 문장에 대해 이미지 생성
      shouldStopImageGeneration.current = false // 중단 플래그 초기화
      let characterAnchor: string | null = null // 캐릭터 앵커 (첫 번째 이미지에서 추출)
      let backgroundStyle: string | null = null // 배경 스타일 (실사화 일관성 유지용)
      let renderingStyle: string | null = null // 그림체/렌더링 스타일 (실사화 일관성 유지용)
      const isRealistic = imageStyle === "realistic" || imageStyle === "realistic2"
      
      for (let i = 0; i < scriptLines.length; i++) {
        // 중단 체크
        if (shouldStopImageGeneration.current) {
          console.log("[v0] 이미지 생성 중단됨")
          // alert(`이미지 생성을 중단했습니다. (${successCount}개 생성 완료)`) // 완료 알림 제거
          break
        }
        
        const line = scriptLines[i]
        setImageGenerationProgress({ current: i + 1, total: scriptLines.length })

        try {
          // API route를 통해 이미지 생성
          console.log(`[v0] 이미지 생성 중... (${i + 1}/${scriptLines.length})`)
          const response = await fetch("/api/generate-image", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
            },
            body: JSON.stringify({
              scriptText: line.text,
              openaiApiKey,
              replicateApiKey,
              category: selectedCategory || "health",
              historyStyle: imageStyle, // 모든 카테고리에서 스타일 적용
              commonStylePrompt, // 공통 스타일 프롬프트 전달
              topic: isCustomTopicSelected ? customTopic : selectedTopic, // 주제 전달 (시대적 배경 파악용)
              characterAnchor: characterAnchor || undefined, // 캐릭터 앵커 전달 (첫 번째 이미지 이후)
              backgroundStyle: backgroundStyle || undefined, // 배경 스타일 전달 (실사화 일관성 유지용)
              renderingStyle: renderingStyle || undefined, // 그림체 스타일 전달 (실사화 일관성 유지용)
            }),
          })

          if (!response.ok) {
            const errorData = await response.json()
            throw new Error(errorData.error || "이미지 생성 실패")
          }

          const data = await response.json()
          console.log(`[v0] 이미지 생성 완료:`, data.imageUrl)

          // 첫 번째 이미지에서 캐릭터 앵커, 배경 스타일, 그림체 추출
          if (i === 0 && data.imageUrl) {
            try {
              const { extractCharacterAnchor, extractBackgroundAndRenderingStyle } = await import("./actions")
              const topic = isCustomTopicSelected ? customTopic : selectedTopic
              
              // 캐릭터 앵커 추출 (인물이 있는 경우)
              if (!characterAnchor) {
                const extractedAnchor = await extractCharacterAnchor(
                  data.imageUrl,
                  line.text,
                  openaiApiKey,
                  topic || undefined
                )
                if (extractedAnchor) {
                  characterAnchor = extractedAnchor
                  console.log("[v0] 캐릭터 앵커 추출 완료:", characterAnchor.substring(0, 100) + "...")
                } else {
                  console.log("[v0] 캐릭터 앵커 추출: 인물 없음 또는 추출 실패")
                }
              }
              
              // 실사화 스타일일 때 배경 스타일과 그림체 추출
              if (isRealistic) {
                const { backgroundStyle: extractedBg, renderingStyle: extractedRendering } = await extractBackgroundAndRenderingStyle(
                  data.imageUrl,
                  openaiApiKey
                )
                if (extractedBg) {
                  backgroundStyle = extractedBg
                  console.log("[v0] 배경 스타일 추출 완료:", backgroundStyle.substring(0, 100) + "...")
                }
                if (extractedRendering) {
                  renderingStyle = extractedRendering
                  console.log("[v0] 그림체 스타일 추출 완료:", renderingStyle.substring(0, 100) + "...")
                }
              } else {
                // 애니메이션 스타일(유럽풍 그래픽 노블 포함)에서도 그림체 스타일 추출 (일관성 유지)
                const isAnimation = imageStyle === "stickman-animation" || imageStyle === "animation2" || imageStyle === "animation3" || imageStyle === "semi-realistic-animation"
                if (isAnimation) {
                  try {
                    const { renderingStyle: extractedRendering } = await extractBackgroundAndRenderingStyle(
                      data.imageUrl,
                      openaiApiKey
                    )
                    if (extractedRendering) {
                      renderingStyle = extractedRendering
                      console.log("[v0] 애니메이션 그림체 스타일 추출 완료:", renderingStyle.substring(0, 100) + "...")
                    }
                  } catch (error) {
                    console.warn("[v0] 애니메이션 그림체 스타일 추출 실패:", error)
                  }
                }
              }
            } catch (error) {
              console.warn("[v0] 스타일 정보 추출 실패, 계속 진행:", error)
            }
          }

          // 이미지가 생성되면 즉시 state 업데이트 (실시간 표시)
          setGeneratedImages((prev) => [
            ...prev,
            {
              lineId: line.id,
              imageUrl: data.imageUrl,
              prompt: data.prompt,
              createdAt: Date.now(), // 이미지 생성 시간 저장
            },
          ])
          successCount++
        } catch (error) {
          console.error(`[v0] 이미지 생성 실패 (줄 ${line.id}):`, error)
          // 실패해도 계속 진행
        }
      }

      console.log("[v0] 모든 이미지 생성 완료, 성공:", successCount, "개")
      if (successCount > 0) playNotificationSound() // 알림음 재생
      
      // 이미지가 하나라도 생성되었으면 완료 표시
      if (successCount > 0) {
        setCompletedSteps((prev) => {
          if (!prev.includes("image")) return [...prev, "image"]
          return prev
        })
        if (!isAutoMode) {
          // alert(`${successCount}개의 이미지가 생성되었습니다!`) // 완료 알림 제거
        }
        
        // 자동화 모드일 때 다음 단계 자동 진행 (TTS 생성)
        if (isAutoMode) {
          console.log("[v0] 자동화 모드: TTS 생성 시작")
          setTimeout(() => handleGenerateTTSForLines(), 2000)
        }
      } else {
        alert("이미지 생성에 실패했습니다. 다시 시도해주세요.")
        if (isAutoMode) {
          setIsAutoMode(false)
          setAutoModeStep("")
        }
      }
    } catch (error) {
      console.error("이미지 생성 실패:", error)
      alert("이미지 생성 중 오류가 발생했습니다.")
      if (isAutoMode) {
        setIsAutoMode(false)
        setAutoModeStep("")
      }
    } finally {
      setIsGeneratingImages(false)
      setImageGenerationProgress({ current: 0, total: 0 })
      shouldStopImageGeneration.current = false // 중단 플래그 초기화
    }
  }


  // 수퍼톤 음성 목록 가져오기
  const fetchSupertoneVoices = async () => {
    setIsLoadingSupertoneVoices(true)
    try {
      const supertoneApiKey = getApiKey("supertone_api_key")
      if (!supertoneApiKey) {
        alert("수퍼톤 API 키가 필요합니다. 설정에서 API 키를 입력해주세요.")
        setIsLoadingSupertoneVoices(false)
        return
      }

      const response = await fetch(`/api/supertone-voices?apiKey=${encodeURIComponent(supertoneApiKey)}`, {
        method: "GET",
        headers: {
          "Content-Type": "application/json",
        },
      })

      if (!response.ok) {
        const errorData = await response.json()
        throw new Error(errorData.error || "음성 목록을 가져오는데 실패했습니다.")
      }

      const data = await response.json()
      if (data.success && data.voices) {
        // 특정 음성 제외: "달팽이A", "기억의정령_알마냐", "틈새의정령_알마냐"
        const excludedNames = ["달팽이A", "기억의정령_알마냐", "틈새의정령_알마냐"]
        const filteredVoices = data.voices.filter((voice: { name: string }) => 
          !excludedNames.some(excluded => voice.name.includes(excluded))
        )
        setSupertoneVoices(filteredVoices)
        // 첫 번째 음성을 기본 선택
        if (filteredVoices.length > 0 && !selectedSupertoneVoiceId) {
          setSelectedSupertoneVoiceId(filteredVoices[0].voice_id)
          setSelectedVoiceId(`supertone-${filteredVoices[0].voice_id}`)
        }
      } else {
        throw new Error(data.error || "음성 목록을 가져오는데 실패했습니다.")
      }
    } catch (error) {
      console.error("수퍼톤 음성 목록 가져오기 실패:", error)
      alert(`수퍼톤 음성 목록을 가져오는데 실패했습니다: ${error instanceof Error ? error.message : "알 수 없는 오류"}`)
    } finally {
      setIsLoadingSupertoneVoices(false)
    }
  }

  // 언어 코드를 한국어로 변환하는 함수
  const languageCodeToKorean = (code: string): string => {
    const languageMap: Record<string, string> = {
      "ar": "아랍어",
      "bg": "불가리아어",
      "cs": "체코어",
      "da": "덴마크어",
      "de": "독일어",
      "el": "그리스어",
      "en": "영어",
      "es": "스페인어",
      "et": "에스토니아어",
      "fi": "핀란드어",
      "fr": "프랑스어",
      "hi": "힌디어",
      "hu": "헝가리어",
      "id": "인도네시아어",
      "it": "이탈리아어",
      "ja": "일본어",
      "ko": "한국어",
      "nl": "네덜란드어",
      "pl": "폴란드어",
      "pt": "포르투갈어",
      "ro": "루마니아어",
      "ru": "러시아어",
      "vi": "베트남어",
    }
    return languageMap[code.toLowerCase()] || code
  }

  // 목소리 미리듣기 함수
  const handlePreviewVoice = async (voiceId: string) => {
    setPreviewingVoiceId(voiceId)
    
    try {
      let response: Response
      
      // 수퍼톤인 경우
      if (voiceId?.startsWith("supertone-")) {
        const actualVoiceId = voiceId.replace("supertone-", "")
        const supertoneApiKey = getApiKey("supertone_api_key")
        
        if (!supertoneApiKey) {
          alert("수퍼톤 API 키가 필요합니다. 설정에서 API 키를 입력해주세요.")
          setPreviewingVoiceId(null)
          return
        }
        
        response = await fetch("/api/supertone-tts", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            text: "여러분 환영합니다",
            voiceId: actualVoiceId,
            apiKey: supertoneApiKey,
            style: selectedSupertoneStyle || "neutral", // 사용자가 선택한 스타일
            language: "ko", // 기본값: 한국어
          }),
        })
      } else if (voiceId?.startsWith("ttsmaker-")) {
        // TTSMaker인 경우
        const voiceName = voiceId.replace("ttsmaker-", "")
        // 남성5는 음높이 -10% (pitch 0.9)
        const pitch = voiceName === "남성5" ? 0.9 : 1.0
        const ttsmakerApiKey = getApiKey("ttsmaker_api_key")
        
        if (!ttsmakerApiKey) {
          alert("TTSMaker API 키가 필요합니다. 설정에서 API 키를 입력해주세요.")
          setPreviewingVoiceId(null)
          return
        }
        
        console.log(`[미리듣기] TTSMaker voice: ${voiceId} -> ${voiceName}, pitch: ${pitch}`)
        response = await fetch("/api/ttsmaker", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            text: "여러분 환영합니다",
            voice: voiceName,
            speed: 1.0,
            pitch: pitch,
            apiKey: ttsmakerApiKey,
          }),
        })
      } else if (voiceId?.startsWith("elevenlabs-")) {
        // ElevenLabs인 경우 (새로운 형식: elevenlabs-{voiceId})
        const actualVoiceId = voiceId.replace("elevenlabs-", "")
        let elevenlabsApiKey = typeof window !== "undefined" 
          ? (localStorage.getItem("elevenlabs_api_key") || "").trim() 
          : null
        
        // localStorage에 없으면 getApiKey로 시도
        if (!elevenlabsApiKey || elevenlabsApiKey.length === 0) {
          const apiKey = getApiKey("elevenlabs")
          elevenlabsApiKey = apiKey !== undefined ? apiKey : null
        }
        
        if (!elevenlabsApiKey || elevenlabsApiKey.length === 0) {
          alert("ElevenLabs API 키가 필요합니다. 설정에서 API 키를 입력해주세요.")
          setPreviewingVoiceId(null)
          return
        }
        
        response = await fetch("/api/elevenlabs-tts", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            text: "여러분 환영합니다",
            voiceId: actualVoiceId,
            apiKey: elevenlabsApiKey,
          }),
        })
      } else {
        // 기본 ElevenLabs 처리 (하위 호환성: voiceId가 직접 ElevenLabs voice ID인 경우)
        let elevenlabsApiKey = typeof window !== "undefined" 
          ? (localStorage.getItem("elevenlabs_api_key") || "").trim() 
          : null
        
        // localStorage에 없으면 getApiKey로 시도
        if (!elevenlabsApiKey || elevenlabsApiKey.length === 0) {
          const apiKey = getApiKey("elevenlabs")
          elevenlabsApiKey = apiKey !== undefined ? apiKey : null
        }
        
        if (!elevenlabsApiKey || elevenlabsApiKey.length === 0) {
          alert("ElevenLabs API 키가 필요합니다. 설정에서 API 키를 입력해주세요.")
          setPreviewingVoiceId(null)
          return
        }
        
        response = await fetch("/api/elevenlabs-tts", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            text: "여러분 환영합니다",
            voiceId: voiceId,
            apiKey: elevenlabsApiKey,
          }),
        })
      }

      if (!response.ok) {
        let errorMessage = "미리듣기 실패"
        try {
          // response를 clone해서 읽기 (원본 response는 나중에 사용할 수 있도록)
          const clonedResponse = response.clone()
          const errorData = await clonedResponse.json()
          errorMessage = errorData.error || errorData.message || `HTTP ${response.status}: ${response.statusText}`
          
          // 404 오류인 경우 더 명확한 메시지
          if (response.status === 404 && errorMessage.includes("not found")) {
            errorMessage = `커스텀 목소리를 찾을 수 없습니다.\n\n${errorMessage}\n\n가능한 원인:\n1. 목소리 ID가 올바르지 않습니다\n2. API 키가 해당 목소리를 생성한 계정의 키가 아닙니다\n3. 목소리가 삭제되었거나 비공개 상태입니다\n\n해결 방법:\n1. 목소리 ID를 다시 확인하세요\n2. 목소리를 생성한 계정의 API 키를 사용하세요\n3. ElevenLabs 대시보드에서 목소리가 존재하는지 확인하세요`
          }
        } catch (e) {
          // JSON 파싱 실패 시 텍스트로 읽기 시도
          try {
            const errorText = await response.text()
            errorMessage = errorText || `HTTP ${response.status}: ${response.statusText}`
          } catch (textError) {
            errorMessage = `HTTP ${response.status}: ${response.statusText}`
          }
        }
        throw new Error(errorMessage)
      }

      const data = await response.json()
      
      if (data.audioUrl) {
        setPreviewAudioUrl(data.audioUrl)
        // 오디오 재생
        const audio = new Audio(data.audioUrl)
        audio.play()
        audio.onended = () => {
          setPreviewingVoiceId(null)
          setPreviewAudioUrl(null)
        }
        audio.onerror = () => {
          setPreviewingVoiceId(null)
          setPreviewAudioUrl(null)
        }
      } else if (data.audioBase64) {
        // Base64를 Blob URL로 변환
        const binaryString = atob(data.audioBase64)
        const bytes = new Uint8Array(binaryString.length)
        for (let i = 0; i < binaryString.length; i++) {
          bytes[i] = binaryString.charCodeAt(i)
        }
        const blob = new Blob([bytes], { type: "audio/mpeg" })
        const audioUrl = URL.createObjectURL(blob)
        setPreviewAudioUrl(audioUrl)
        
        const audio = new Audio(audioUrl)
        audio.play()
        audio.onended = () => {
          URL.revokeObjectURL(audioUrl)
          setPreviewingVoiceId(null)
          setPreviewAudioUrl(null)
        }
        audio.onerror = () => {
          URL.revokeObjectURL(audioUrl)
          setPreviewingVoiceId(null)
          setPreviewAudioUrl(null)
        }
      }
    } catch (error) {
      console.error("미리듣기 실패:", error)
      alert(`미리듣기에 실패했습니다: ${error instanceof Error ? error.message : "알 수 없는 오류"}`)
      setPreviewingVoiceId(null)
      setPreviewAudioUrl(null)
    }
  }

  // 6.25만 한글로 변환하는 함수 (6.25 -> 육이오)
  const convertNumbersToKorean = (text: string): string => {
    // 6.25만 "육이오"로 변환
    return text.replace(/6\.25/g, "육이오")
  }

  // TTS 생성 재시도 헬퍼 함수
  const generateTTSWithRetry = async (
    line: { id: number; text: string },
    selectedVoiceId: string,
    maxRetries: number = 5,
    abortSignal?: AbortSignal
  ): Promise<{ audioUrl: string; audioBase64: string; alignment?: any }> => {
    let lastError: Error | null = null
    
    // 숫자를 한글로 변환
    let convertedText = convertNumbersToKorean(line.text)
    
    // 번역이 필요한 경우 (한국어가 아닌 경우)
    if (ttsTargetLanguage !== "ko") {
      try {
        const openaiApiKey = getApiKey("openai_api_key") || getApiKey("openai") || getApiKey("gpt_api_key") || getApiKey("chatgpt_api_key")
        
        if (!openaiApiKey) {
          console.warn("[TTS 번역] OpenAI API 키가 없어 번역을 건너뜁니다. 원본 텍스트를 사용합니다.")
        } else {
          console.log(`[TTS 번역] ${ttsTargetLanguage}로 번역 시작: "${convertedText.substring(0, 30)}..."`)
          
          const translateResponse = await fetch("/api/translate", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
            },
            body: JSON.stringify({
              text: convertedText,
              sourceLanguage: "ko",
              targetLanguage: ttsTargetLanguage,
              apiKey: openaiApiKey,
            }),
            signal: abortSignal,
          })
          
          if (translateResponse.ok) {
            const translateData = await translateResponse.json()
            if (translateData.translatedText) {
              convertedText = translateData.translatedText
              console.log(`[TTS 번역] 번역 완료: "${convertedText.substring(0, 30)}..."`)
            }
          } else {
            console.warn("[TTS 번역] 번역 실패, 원본 텍스트 사용")
          }
        }
      } catch (error) {
        console.warn("[TTS 번역] 번역 중 오류 발생, 원본 텍스트 사용:", error)
      }
    }
    
    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      // 중지 요청 확인
      if (abortSignal?.aborted || shouldStopTTSGeneration.current) {
        throw new Error("TTS 생성이 중지되었습니다.")
      }
      
      try {
        let response: Response
        
        // TTSMaker인 경우
        if (selectedVoiceId?.startsWith("ttsmaker-")) {
          // TTSMaker인 경우
          const voiceName = selectedVoiceId.replace("ttsmaker-", "")
          const pitch = voiceName === "남성5" ? 0.9 : 1.0
          const ttsmakerApiKey = getApiKey("ttsmaker_api_key")
          
          if (!ttsmakerApiKey) {
            throw new Error("TTSMaker API 키가 필요합니다. 설정에서 API 키를 입력해주세요.")
          }
          
          response = await fetch("/api/ttsmaker", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
            },
            body: JSON.stringify({
              text: convertedText,
              voice: voiceName,
              speed: 1.0,
              pitch: pitch,
              apiKey: ttsmakerApiKey,
            }),
            signal: abortSignal, // AbortSignal 전달
          })
        } else if (selectedVoiceId?.startsWith("supertone-")) {
          // 수퍼톤인 경우
          const voiceId = selectedVoiceId.replace("supertone-", "")
          // 미리듣기와 동일한 방식으로 API 키 가져오기
          let supertoneApiKey = typeof window !== "undefined" 
            ? (localStorage.getItem("supertone_api_key") || "").trim() 
            : null
          
          // localStorage에 없으면 getApiKey로 시도
          if (!supertoneApiKey || supertoneApiKey.length === 0) {
            const apiKey = getApiKey("supertone_api_key")
            supertoneApiKey = apiKey !== undefined ? apiKey : null
          }
          
          if (!supertoneApiKey || supertoneApiKey.length === 0) {
            throw new Error("수퍼톤 API 키가 필요합니다. 설정에서 API 키를 입력해주세요.")
          }
          
          response = await fetch("/api/supertone-tts", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
            },
            body: JSON.stringify({
              text: convertedText,
              voiceId: voiceId,
              apiKey: supertoneApiKey,
              style: selectedSupertoneStyle || "neutral", // 사용자가 선택한 스타일
              language: ttsTargetLanguage, // 선택한 언어로 설정
            }),
            signal: abortSignal, // AbortSignal 전달
          })
        } else if (selectedVoiceId?.startsWith("elevenlabs-")) {
          // ElevenLabs인 경우 (새로운 형식: elevenlabs-{voiceId})
          const voiceId = selectedVoiceId.replace("elevenlabs-", "")
          // 미리듣기와 동일한 방식으로 API 키 가져오기
          let elevenlabsApiKey = getApiKey("elevenlabs_api_key") ?? null
          
          console.log(`[TTS 생성] ElevenLabs API 키 확인 (getApiKey) - 존재: ${!!elevenlabsApiKey}, 길이: ${elevenlabsApiKey?.length || 0}`)
          
          // getApiKey로 못 찾으면 localStorage에서 직접 가져오기 (fallback)
          if (!elevenlabsApiKey || elevenlabsApiKey.length === 0) {
            elevenlabsApiKey = typeof window !== "undefined" 
              ? (localStorage.getItem("elevenlabs_api_key") || "").trim() || null
              : null
            console.log(`[TTS 생성] ElevenLabs API 키 확인 (localStorage 직접) - 존재: ${!!elevenlabsApiKey}, 길이: ${elevenlabsApiKey?.length || 0}`)
          }
          
          if (!elevenlabsApiKey || elevenlabsApiKey.length === 0) {
            throw new Error("❌ ElevenLabs API 키가 필요합니다.\n\n해결 방법:\n1. 설정에서 ElevenLabs API 키를 입력하세요\n2. API 키가 올바른지 확인하세요")
          }
          
          response = await fetch("/api/elevenlabs-tts", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
            },
            body: JSON.stringify({
              text: convertedText,
              voiceId: voiceId,
              apiKey: elevenlabsApiKey,
            }),
            signal: abortSignal, // AbortSignal 전달
          })
        } else {
          // 기본 ElevenLabs 처리 (하위 호환성: selectedVoiceId가 직접 ElevenLabs voice ID인 경우)
          // 미리듣기와 동일한 방식으로 API 키 가져오기
          let elevenlabsApiKey = getApiKey("elevenlabs_api_key") ?? null
          
          console.log(`[TTS 생성] ElevenLabs API 키 확인 (getApiKey) - 존재: ${!!elevenlabsApiKey}, 길이: ${elevenlabsApiKey?.length || 0}`)
          
          // getApiKey로 못 찾으면 localStorage에서 직접 가져오기 (fallback)
          if (!elevenlabsApiKey || elevenlabsApiKey.length === 0) {
            elevenlabsApiKey = typeof window !== "undefined" 
              ? (localStorage.getItem("elevenlabs_api_key") || "").trim() || null
              : null
            console.log(`[TTS 생성] ElevenLabs API 키 확인 (localStorage 직접) - 존재: ${!!elevenlabsApiKey}, 길이: ${elevenlabsApiKey?.length || 0}`)
          }
          
          if (!elevenlabsApiKey || elevenlabsApiKey.length === 0) {
            throw new Error("❌ ElevenLabs API 키가 필요합니다.\n\n해결 방법:\n1. 설정에서 ElevenLabs API 키를 입력하세요\n2. API 키가 올바른지 확인하세요")
          }
          
          response = await fetch("/api/elevenlabs-tts", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
            },
            body: JSON.stringify({
              text: convertedText,
              voiceId: selectedVoiceId,
              apiKey: elevenlabsApiKey,
            }),
            signal: abortSignal, // AbortSignal 전달
          })
        }

        if (!response.ok) {
          let errorMessage = "TTS 생성 실패"
          let apiKeyName = ""
          
          // 사용 중인 API 키 이름 확인
          if (selectedVoiceId?.startsWith("ttsmaker-")) {
            apiKeyName = "TTSMaker API 키"
          } else if (selectedVoiceId?.startsWith("supertone-")) {
            apiKeyName = "수퍼톤(SuperTone) API 키"
          } else {
            apiKeyName = "ElevenLabs API 키"
          }
          
          try {
            const errorData = await response.json()
            const baseError = errorData.error || errorData.message || `HTTP ${response.status}: ${response.statusText}`
            
            // API 키 관련 오류인지 확인
            if (response.status === 401 || response.status === 403 || 
                baseError.toLowerCase().includes("api key") || 
                baseError.toLowerCase().includes("unauthorized") ||
                baseError.toLowerCase().includes("forbidden") ||
                baseError.toLowerCase().includes("인증") ||
                baseError.toLowerCase().includes("키")) {
              errorMessage = `❌ ${apiKeyName} 오류\n\n${baseError}\n\n해결 방법:\n1. 설정에서 ${apiKeyName}를 확인하세요\n2. API 키가 올바른지 확인하세요\n3. API 키의 사용량이 초과되지 않았는지 확인하세요`
            } else if (response.status === 429 || baseError.toLowerCase().includes("rate limit") || baseError.toLowerCase().includes("quota")) {
              errorMessage = `❌ ${apiKeyName} 사용량 초과\n\n${baseError}\n\n해결 방법:\n1. API 키의 사용량 한도를 확인하세요\n2. 잠시 후 다시 시도하세요\n3. 다른 API 키를 사용하세요`
            } else {
              errorMessage = `❌ TTS 생성 실패 (${apiKeyName})\n\n${baseError}\n\n브라우저 콘솔(F12)에서 자세한 오류를 확인해주세요.`
            }
          } catch (e) {
            const errorText = await response.text()
            const baseError = errorText || `HTTP ${response.status}: ${response.statusText}`
            
            if (response.status === 401 || response.status === 403) {
              errorMessage = `❌ ${apiKeyName} 인증 실패\n\n${baseError}\n\n해결 방법:\n1. 설정에서 ${apiKeyName}를 확인하세요\n2. API 키가 올바른지 확인하세요`
            } else {
              errorMessage = `❌ TTS 생성 실패 (${apiKeyName})\n\n${baseError}`
            }
          }
          throw new Error(errorMessage)
        }

        const data = await response.json()
        
        if (!data.audioBase64 && !data.audioUrl) {
          throw new Error("TTS 응답에 오디오 데이터가 없습니다.")
        }
        
        // Whisper align API 호출 제거 (STT 불필요, 텍스트 길이 비율로 타이밍 계산)
        // ElevenLabs alignment만 사용 (있는 경우)
        const alignment = data.alignment
        
        // 성공 시 반환 (alignment 데이터 포함)
        return {
          audioUrl: data.audioUrl,
          audioBase64: data.audioBase64,
          alignment: alignment || undefined, // alignment 데이터 포함
        }
      } catch (error) {
        lastError = error instanceof Error ? error : new Error(String(error))
        console.warn(`[TTS 재시도] 시도 ${attempt}/${maxRetries} 실패 (줄 ${line.id}):`, lastError.message)
        
        // 마지막 시도가 아니면 대기 후 재시도
        if (attempt < maxRetries) {
          const delay = Math.min(1000 * Math.pow(2, attempt - 1), 10000) // 지수 백오프, 최대 10초
          console.log(`[TTS 재시도] ${delay}ms 후 재시도...`)
          await new Promise(resolve => setTimeout(resolve, delay))
        }
      }
    }
    
    // 모든 재시도 실패
    throw lastError || new Error("TTS 생성에 실패했습니다.")
  }

  // 개별 문장 TTS 생성 핸들러
  const handleGenerateTTSForSingleLine = async (lineId: number) => {
    // 먼저 scriptLines에서 찾기
    let line = scriptLines.find((l) => l.id === lineId)
    
    // scriptLines에서 찾지 못했고 decomposedScenes가 있으면 파싱해서 찾기
    if (!line && decomposedScenes && decomposedScenes.trim().length > 0) {
      const sceneBlocks = decomposedScenes.split(/(?=씬\s+\d+)/).filter(block => block.trim().length > 0)
      let currentLineId = 1
      
      for (const sceneBlock of sceneBlocks) {
        const sceneNumMatch = sceneBlock.match(/씬\s+(\d+)/)
        if (!sceneNumMatch) continue
        
        const imageRegex = /\[장면\s+(\d+)\]\s*\n([\s\S]*?)(?=\[장면\s+\d+\]|씬\s+\d+|$)/g
        let imageMatch
        
        while ((imageMatch = imageRegex.exec(sceneBlock)) !== null) {
          const imageText = imageMatch[2].trim()
          
          if (imageText) {
            if (currentLineId === lineId) {
              // 해당 lineId에 맞는 텍스트를 찾았음
              line = {
                id: lineId,
                text: imageText,
              }
              break
            }
            currentLineId++
          }
        }
        
        if (line) break
      }
    }
    
    if (!line) {
      alert("문장을 찾을 수 없습니다.")
      return
    }

    // TTSMaker, ElevenLabs, 수퍼톤은 API 키 필요
    if (selectedVoiceId?.startsWith("ttsmaker-")) {
      const ttsmakerApiKey = getApiKey("ttsmaker_api_key")
      if (!ttsmakerApiKey) {
        alert("TTSMaker API 키가 필요합니다. 설정에서 API 키를 입력해주세요.")
        return
      }
    } else if (selectedVoiceId?.startsWith("supertone-")) {
      // 미리듣기와 동일한 방식으로 API 키 가져오기
      let supertoneApiKey = typeof window !== "undefined" 
        ? (localStorage.getItem("supertone_api_key") || "").trim() 
        : null
      
      // localStorage에 없으면 getApiKey로 시도
      if (!supertoneApiKey || supertoneApiKey.length === 0) {
        const apiKey = getApiKey("supertone_api_key")
        supertoneApiKey = apiKey !== undefined ? apiKey : null
      }
      
      if (!supertoneApiKey || supertoneApiKey.length === 0) {
        alert("수퍼톤 API 키가 필요합니다. 설정에서 API 키를 입력해주세요.")
        return
      }
    } else {
      // 미리듣기와 동일한 방식으로 API 키 가져오기
      let elevenlabsApiKey = typeof window !== "undefined" 
        ? (localStorage.getItem("elevenlabs_api_key") || "").trim() 
        : null
      
      // localStorage에 없으면 getApiKey로 시도
      if (!elevenlabsApiKey || elevenlabsApiKey.length === 0) {
        const apiKey = getApiKey("elevenlabs")
        elevenlabsApiKey = apiKey !== undefined ? apiKey : null
      }
      
      if (!elevenlabsApiKey || elevenlabsApiKey.length === 0) {
        alert("ElevenLabs API 키가 필요합니다. 설정에서 API 키를 입력해주세요.")
        return
      }
    }

    // 이미 생성된 TTS가 있는지 확인
    const existingAudio = generatedAudios.find((audio) => audio.lineId === lineId)
    if (existingAudio) {
      const confirmReplace = confirm("이미 생성된 TTS가 있습니다. 다시 생성하시겠습니까?")
      if (!confirmReplace) return
      
      // 기존 TTS 제거
      setGeneratedAudios((prev) => prev.filter((audio) => audio.lineId !== lineId))
    }

    setGeneratingTTSForLine((prev) => new Set(prev).add(lineId))

    try {
      console.log(`[개별 TTS] 문장 ${lineId} TTS 생성 시작: ${line.text.substring(0, 30)}...`)
      
      // 재시도 로직이 포함된 TTS 생성
      const data = await generateTTSWithRetry(line, selectedVoiceId)
      
      console.log(`[개별 TTS] 문장 ${lineId} TTS 생성 완료`)

      // TTS가 생성되면 state 업데이트
      setGeneratedAudios((prev) => {
        // 기존 항목 제거 (있으면)
        const filtered = prev.filter((audio) => audio.lineId !== lineId)
        return [
          ...filtered,
          {
            lineId: line.id,
            audioUrl: data.audioUrl,
            audioBase64: data.audioBase64,
          },
        ]
      })
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error)
      console.error(`[개별 TTS] 문장 ${lineId} TTS 생성 실패:`, errorMessage)
      alert(`문장 ${lineId}의 TTS 생성에 실패했습니다: ${errorMessage}`)
    } finally {
      setGeneratingTTSForLine((prev) => {
        const newSet = new Set(prev)
        newSet.delete(lineId)
        return newSet
      })
    }
  }

  // TTS 생성 핸들러 (문장 리스트 기반)
  const handleGenerateTTSForLines = async () => {
    if (scriptLines.length === 0) {
      alert("생성된 문장 리스트가 없습니다. 먼저 대본을 생성해주세요.")
      return
    }

    // TTSMaker, ElevenLabs, 수퍼톤은 API 키 필요
    if (selectedVoiceId?.startsWith("supertone-")) {
      // 미리듣기와 동일한 방식으로 API 키 가져오기
      let supertoneApiKey = typeof window !== "undefined" 
        ? (localStorage.getItem("supertone_api_key") || "").trim() 
        : null
      
      // localStorage에 없으면 getApiKey로 시도
      if (!supertoneApiKey || supertoneApiKey.length === 0) {
        const apiKey = getApiKey("supertone_api_key")
        supertoneApiKey = apiKey !== undefined ? apiKey : null
      }
      
      if (!supertoneApiKey || supertoneApiKey.length === 0) {
        alert("수퍼톤 API 키가 필요합니다. 설정에서 API 키를 입력해주세요.")
        if (isAutoMode) {
          setIsAutoMode(false)
          setAutoModeStep("")
        }
        return
      }
    } else if (!selectedVoiceId?.startsWith("ttsmaker-")) {
      // 미리듣기와 동일한 방식으로 API 키 가져오기
      let elevenlabsApiKey = typeof window !== "undefined" 
        ? (localStorage.getItem("elevenlabs_api_key") || "").trim() 
        : null
      
      // localStorage에 없으면 getApiKey로 시도
      if (!elevenlabsApiKey || elevenlabsApiKey.length === 0) {
        const apiKey = getApiKey("elevenlabs")
        elevenlabsApiKey = apiKey !== undefined ? apiKey : null
      }
      
      if (!elevenlabsApiKey || elevenlabsApiKey.length === 0) {
        alert("ElevenLabs API 키가 필요합니다. 설정에서 API 키를 입력해주세요.")
        if (isAutoMode) {
          setIsAutoMode(false)
          setAutoModeStep("")
        }
        return
      }
    }

    setIsGeneratingTTS(true)
    shouldStopTTSGeneration.current = false // 중단 플래그 초기화
    ttsAbortControllerRef.current = new AbortController() // 새로운 AbortController 생성
    if (isAutoMode) {
      setAutoModeStep("TTS 생성 중...")
      setAutoModeProgress({ current: "5/7", total: 7 })
    }
    
    // 씬별 처리 여부 확인
    const useSceneBasedTTS = decomposedScenes && decomposedScenes.trim().length > 0
    
    if (useSceneBasedTTS) {
      console.log("[TTS] 씬별 TTS 생성 모드 사용")
      
      // 씬별로 파싱
      const sceneBlocks = decomposedScenes.split(/(?=씬\s+\d+)/).filter(block => block.trim().length > 0)
      const parsedScenes: Array<{
        sceneNumber: number
        scenes: Array<{ imageNumber: number; text: string }>
      }> = []
      
      for (const sceneBlock of sceneBlocks) {
        const sceneNumMatch = sceneBlock.match(/씬\s+(\d+)/)
        if (!sceneNumMatch) continue
        
        const sceneNum = parseInt(sceneNumMatch[1])
        const sceneImages: Array<{ imageNumber: number; text: string }> = []
        
        const imageRegex = /\[장면\s+(\d+)\]\s*\n([\s\S]*?)(?=\[장면\s+\d+\]|씬\s+\d+|$)/g
        let imageMatch
        
        while ((imageMatch = imageRegex.exec(sceneBlock)) !== null) {
          const imageNum = parseInt(imageMatch[1])
          const imageText = imageMatch[2].trim()
          
          if (imageText) {
            sceneImages.push({
              imageNumber: imageNum,
              text: imageText,
            })
          }
        }
        
        if (sceneImages.length > 0) {
          parsedScenes.push({
            sceneNumber: sceneNum,
            scenes: sceneImages,
          })
        }
      }
      
      console.log(`[TTS] 파싱된 씬 수: ${parsedScenes.length}`)
      
      // 씬 번호 순서대로 정렬 (중요: TTS 생성 순서와 일치시켜야 함)
      parsedScenes.sort((a, b) => a.sceneNumber - b.sceneNumber)
      
      parsedScenes.forEach(scene => {
        console.log(`[TTS] 씬 ${scene.sceneNumber}: ${scene.scenes.length}개의 장면 발견`)
        scene.scenes.forEach(img => {
          console.log(`[TTS]   - 장면 ${img.imageNumber}: "${img.text.substring(0, 50)}..."`)
        })
      })
      
      // 각 장면의 텍스트를 그대로 하나의 TTS로 생성 (문장 분리 없이)
      const sceneTextsForTTS: Array<{ sceneNumber: number; imageNumber: number; text: string; lineId: number }> = []
      let lineIdCounter = 1
      
      for (const parsedScene of parsedScenes) {
        // 장면 번호 순서대로 정렬 (중요: TTS 생성 순서와 일치시켜야 함)
        const sortedScenes = [...parsedScene.scenes].sort((a, b) => a.imageNumber - b.imageNumber)
        
        for (const scene of sortedScenes) {
          // 각 장면의 텍스트를 그대로 사용 (문장 분리 없이)
          const text = scene.text.trim()
          
          if (text.length > 0) {
            sceneTextsForTTS.push({
              sceneNumber: parsedScene.sceneNumber,
              imageNumber: scene.imageNumber,
              text: text,
              lineId: lineIdCounter++,
            })
            
            console.log(`[TTS] 씬 ${parsedScene.sceneNumber} 장면 ${scene.imageNumber} 추가: "${text.substring(0, 50)}..."`)
          }
        }
      }
      
      console.log(`[TTS] 총 ${sceneTextsForTTS.length}개의 장면에 대해 TTS 생성`)
      
      setTtsGenerationProgress({ current: 0, total: sceneTextsForTTS.length })
      setGeneratedAudios([])
      
      let successCount = 0
      let currentProgress = 0
      
      try {
        // 각 장면별로 TTS 생성
        console.log(`[TTS] TTS 생성 시작: 총 ${sceneTextsForTTS.length}개 문장`)
        console.log(`[TTS] 장면별 분포:`, sceneTextsForTTS.reduce((acc, item) => {
          const key = `씬${item.sceneNumber}-장면${item.imageNumber}`
          acc[key] = (acc[key] || 0) + 1
          return acc
        }, {} as Record<string, number>))
        
        for (let i = 0; i < sceneTextsForTTS.length; i++) {
          // 중지 요청 확인
          if (shouldStopTTSGeneration.current) {
            console.log("[TTS] 사용자가 TTS 생성을 중지했습니다.")
            break
          }
          
          const sceneText = sceneTextsForTTS[i]
          currentProgress++
          setTtsGenerationProgress({ current: currentProgress, total: sceneTextsForTTS.length })
          
          try {
            console.log(`[TTS] [${i + 1}/${sceneTextsForTTS.length}] 씬 ${sceneText.sceneNumber} 장면 ${sceneText.imageNumber} TTS 생성 시작: "${sceneText.text.substring(0, 50)}..."`)
            
            const data = await generateTTSWithRetry(
              { id: sceneText.lineId, text: sceneText.text },
              selectedVoiceId,
              5,
              ttsAbortControllerRef.current?.signal
            )
            
            console.log(`[TTS] [${i + 1}/${sceneTextsForTTS.length}] 씬 ${sceneText.sceneNumber} 장면 ${sceneText.imageNumber} TTS 생성 완료`)
            
            setGeneratedAudios((prev) => {
              const newAudios = [
                ...prev,
                {
                  lineId: sceneText.lineId,
                  audioUrl: data.audioUrl,
                  audioBase64: data.audioBase64,
                  alignment: data.alignment || undefined, // alignment 데이터 저장
                },
              ]
              console.log(`[TTS] 현재 생성된 TTS 개수: ${newAudios.length}`)
              return newAudios
            })
            successCount++
          } catch (error) {
            const errorMessage = error instanceof Error ? error.message : String(error)
            console.error(`[TTS] [${i + 1}/${sceneTextsForTTS.length}] 씬 ${sceneText.sceneNumber} 장면 ${sceneText.imageNumber} TTS 생성 실패:`, errorMessage)
          }
        }
        
        console.log("[TTS] 모든 장면별 TTS 생성 완료, 성공:", successCount, "개 / 전체:", sceneTextsForTTS.length, "개")
        
        if (successCount > 0) {
          console.log("[TTS] TTS 생성 완료 - 사이드바 완료 표시 업데이트")
          setCompletedSteps((prev) => {
            if (!prev.includes("video")) {
              console.log("[TTS] 'video' 단계를 완료 목록에 추가")
              return [...prev, "video"]
            }
            console.log("[TTS] 'video' 단계는 이미 완료 목록에 있음")
            return prev
          })
          
          if (!isAutoMode) {
            if (successCount < sceneTextsForTTS.length) {
              // alert(`${successCount}개의 TTS가 생성되었습니다. (${sceneTextsForTTS.length - successCount}개 실패)\n\n실패한 항목은 브라우저 콘솔을 확인해주세요.`) // 완료 알림 제거
            } else {
              // alert(`${successCount}개의 TTS가 모두 생성되었습니다!`) // 완료 알림 제거
            }
          }
          
          if (isAutoMode) {
            console.log("[TTS] 자동화 모드: 영상 생성 시작")
            setTimeout(() => handleRenderVideo(), 2000)
          }
        } else {
          // 사용 중인 TTS 서비스 확인
          let apiKeyName = "ElevenLabs API 키"
          if (selectedVoiceId?.startsWith("ttsmaker-")) {
            apiKeyName = "TTSMaker API 키"
          } else if (selectedVoiceId?.startsWith("supertone-")) {
            apiKeyName = "수퍼톤(SuperTone) API 키"
          }
          
          const errorMessage = `❌ TTS 생성에 실패했습니다.\n\n사용 중인 API: ${apiKeyName}\n\n가능한 원인:\n1. ${apiKeyName}가 올바르지 않습니다\n2. ${apiKeyName}의 사용량이 초과되었습니다\n3. 네트워크 연결 문제\n\n해결 방법:\n1. 설정에서 ${apiKeyName}를 확인하세요\n2. API 키가 올바른지 확인하세요\n3. 브라우저 콘솔(F12)에서 자세한 오류를 확인해주세요.`
          alert(errorMessage)
          if (isAutoMode) {
            setIsAutoMode(false)
            setAutoModeStep("")
          }
        }
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : String(error)
        console.error("TTS 생성 실패:", errorMessage, error)
        
        // 사용 중인 TTS 서비스 확인
        let apiKeyName = "ElevenLabs API 키"
        if (selectedVoiceId?.startsWith("ttsmaker-")) {
          apiKeyName = "TTSMaker API 키"
        } else if (selectedVoiceId?.startsWith("supertone-")) {
          apiKeyName = "수퍼톤(SuperTone) API 키"
        }
        
        // 오류 메시지에 API 키 정보 포함
        let finalErrorMessage = `❌ TTS 생성 중 오류가 발생했습니다.\n\n사용 중인 API: ${apiKeyName}\n\n오류 내용:\n${errorMessage}`
        
        // API 키 관련 오류인지 확인
        if (errorMessage.toLowerCase().includes("api key") ||
            errorMessage.toLowerCase().includes("api 키") ||
            errorMessage.toLowerCase().includes("unauthorized") ||
            errorMessage.toLowerCase().includes("인증")) {
          finalErrorMessage += `\n\n해결 방법:\n1. 설정에서 ${apiKeyName}를 확인하세요\n2. API 키가 올바른지 확인하세요`
        }
        
        alert(finalErrorMessage)
        if (isAutoMode) {
          setIsAutoMode(false)
          setAutoModeStep("")
        }
      } finally {
        setIsGeneratingTTS(false)
        setTtsGenerationProgress({ current: 0, total: 0 })
        shouldStopTTSGeneration.current = false // 중단 플래그 초기화
      }
      
      return
    }
    
    // 기존 로직 (씬별 TTS가 아닌 경우)
    setTtsGenerationProgress({ current: 0, total: scriptLines.length })
    // 기존 오디오 초기화
    setGeneratedAudios([])

    let successCount = 0

    try {
      for (let i = 0; i < scriptLines.length; i++) {
        // 중지 요청 확인
        if (shouldStopTTSGeneration.current) {
          console.log("[TTS] 사용자가 TTS 생성을 중지했습니다.")
          break
        }
        
        const line = scriptLines[i]
        setTtsGenerationProgress({ current: i + 1, total: scriptLines.length })

        try {
          console.log(`[v0] TTS 생성 시작 (${i + 1}/${scriptLines.length}): ${line.text.substring(0, 30)}...`)
          
          // 재시도 로직이 포함된 TTS 생성
          const data = await generateTTSWithRetry(
            line,
            selectedVoiceId,
            5,
            ttsAbortControllerRef.current?.signal
          )
          
          console.log(`[v0] TTS 생성 완료 (줄 ${line.id}):`, data.audioUrl ? "URL 있음" : "URL 없음", data.audioBase64 ? "Base64 있음" : "Base64 없음")

          // TTS가 생성되면 즉시 state 업데이트 (실시간 표시)
          setGeneratedAudios((prev) => [
            ...prev,
            {
              lineId: line.id,
              audioUrl: data.audioUrl,
              audioBase64: data.audioBase64,
            },
          ])
          successCount++
        } catch (error) {
          const errorMessage = error instanceof Error ? error.message : String(error)
          console.error(`[v0] TTS 생성 최종 실패 (줄 ${line.id}):`, errorMessage)
          console.error(`[v0] 실패한 텍스트:`, line.text.substring(0, 50) + "...")
          // 실패해도 계속 진행하되, 사용자에게 알림
          if (i === 0) {
            // 첫 번째 실패 시에만 경고 (모든 실패는 마지막에 요약)
            console.warn(`[v0] 첫 번째 TTS 생성 실패. 계속 진행합니다...`)
          }
        }
      }

      console.log("[v0] 모든 TTS 생성 완료, 성공:", successCount, "개 / 전체:", scriptLines.length, "개")
      if (successCount > 0) playNotificationSound() // 알림음 재생

      // TTS가 하나라도 생성되었으면 완료 표시
      if (successCount > 0) {
        setCompletedSteps((prev) => {
          if (!prev.includes("video")) return [...prev, "video"]
          return prev
        })
        
        if (!isAutoMode) {
          if (successCount < scriptLines.length) {
            // alert(`${successCount}개의 TTS가 생성되었습니다. (${scriptLines.length - successCount}개 실패)\n\n실패한 항목은 브라우저 콘솔을 확인해주세요.`) // 완료 알림 제거
          } else {
            // alert(`${successCount}개의 TTS가 모두 생성되었습니다!`) // 완료 알림 제거
          }
        }
        
        // 자동화 모드일 때 다음 단계 자동 진행 (영상 생성)
        if (isAutoMode) {
          console.log("[v0] 자동화 모드: 영상 생성 시작")
          setTimeout(() => handleRenderVideo(), 2000)
        }
      } else {
        // 사용 중인 TTS 서비스 확인
        let apiKeyName = "ElevenLabs API 키"
        if (selectedVoiceId?.startsWith("ttsmaker-")) {
          apiKeyName = "TTSMaker API 키"
        } else if (selectedVoiceId?.startsWith("supertone-")) {
          apiKeyName = "수퍼톤(SuperTone) API 키"
        }
        
        const errorMessage = `❌ TTS 생성에 실패했습니다.\n\n사용 중인 API: ${apiKeyName}\n\n가능한 원인:\n1. ${apiKeyName}가 올바르지 않습니다\n2. ${apiKeyName}의 사용량이 초과되었습니다\n3. 네트워크 연결 문제\n\n해결 방법:\n1. 설정에서 ${apiKeyName}를 확인하세요\n2. API 키가 올바른지 확인하세요\n3. 브라우저 콘솔(F12)에서 자세한 오류를 확인해주세요.`
        alert(errorMessage)
        if (isAutoMode) {
          setIsAutoMode(false)
          setAutoModeStep("")
        }
      }
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error)
      console.error("TTS 생성 실패:", errorMessage, error)
      
      // 사용 중인 TTS 서비스 확인
      let apiKeyName = "ElevenLabs API 키"
      if (selectedVoiceId?.startsWith("ttsmaker-")) {
        apiKeyName = "TTSMaker API 키"
      } else if (selectedVoiceId?.startsWith("supertone-")) {
        apiKeyName = "수퍼톤(SuperTone) API 키"
      }
      
      // 오류 메시지에 API 키 정보 포함
      let finalErrorMessage = `❌ TTS 생성 중 오류가 발생했습니다.\n\n사용 중인 API: ${apiKeyName}\n\n오류 내용:\n${errorMessage}`
      
      // API 키 관련 오류인지 확인
      if (errorMessage.toLowerCase().includes("api key") ||
          errorMessage.toLowerCase().includes("api 키") ||
          errorMessage.toLowerCase().includes("unauthorized") ||
          errorMessage.toLowerCase().includes("인증")) {
        finalErrorMessage += `\n\n해결 방법:\n1. 설정에서 ${apiKeyName}를 확인하세요\n2. API 키가 올바른지 확인하세요`
      }
      
      alert(finalErrorMessage)
      if (isAutoMode) {
        setIsAutoMode(false)
        setAutoModeStep("")
      }
    } finally {
      setIsGeneratingTTS(false)
      setTtsGenerationProgress({ current: 0, total: 0 })
    }
  }

  const handleAutoGenerateImages = async () => {
    if (!script) {
      alert("대본이 필요합니다.")
      return
    }

    setIsLoadingAutoImages(true)
    try {
      console.log("[v0] 대본 분석 및 이미지 자동 생성 시작")

      // 1. 대본에서 키워드 추출
      const keywords = await extractKeywordsFromScript(script)
      console.log("[v0] 추출된 키워드:", keywords)

      // 2. 각 키워드로 이미지 검색
      const keywordResults = []
      for (let i = 0; i < keywords.length; i++) {
        const item = keywords[i]
        try {
          const response = await fetch(`/api/unsplash-search?query=${encodeURIComponent(item.keyword)}`)
          const data = await response.json()

          if (data.images && data.images.length > 0) {
            const image = data.images[0] // 첫 번째 이미지 선택
            keywordResults.push({
              keyword: item.keyword,
              time: i * 15, // 각 키워드마다 15초 간격으로 시간 할당
              imageUrl: image.url,
            })
          }
        } catch (error) {
          console.error(`이미지 검색 실패 (${item.keyword}):`, error)
        }
      }

      const newAutoImages: AutoImage[] = keywordResults.map((result) => ({
        id: `auto-${Date.now()}-${Math.random()}`,
        url: result.imageUrl,
        keyword: result.keyword,
        startTime: result.time,
        endTime: result.time + 15, // 15초 동안 표시
        motion: ["zoom-in", "zoom-out", "pan-left", "pan-right", "static"][
          Math.floor(Math.random() * 5)
        ] as AutoImage["motion"],
      }))

      setAutoImages(newAutoImages)
      console.log("[v0] 자동 이미지 생성 완료:", newAutoImages.length, "개")
      alert(`${newAutoImages.length}개의 이미지가 자동으로 추가되었습니다!`)
    } catch (error) {
      console.error("자동 이미지 생성 실패:", error)
      alert("자동 이미지 생성에 실패했습니다.")
    } finally {
      setIsLoadingAutoImages(false)
    }
  }

  // CHANGE: handleGenerateVideo를 API Route 호출로 변경
  const handleGenerateVideo = async () => {
    // Using script and generatedImage as they are defined in the component's state
    if (!script.trim()) {
      alert("대본을 입력해주세요.")
      return
    }

    setIsGeneratingVideo(true)
    setGeneratingVideoProgress(0) // Reset progress
    setRenderingStatusMessage("영상 생성 중...")

    try {
      console.log("[v0] 영상 생성 시작")

      const response = await fetch("/api/generate-video", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          script: script,
          voiceModel: "ko-KR-Neural2-C",
          autoImages: autoImages,
          userApiKey: userTtsApiKey, // Using the state variable for the API key
          characterImage: generatedImage, // Passing the generated character image
        }),
      })

      if (!response.ok) {
        const errorData = await response.json()
        throw new Error(errorData.error || "영상 생성 실패")
      }

      // Stream the response for progress updates
      const reader = response.body?.getReader()
      let receivedLength = 0
      const chunks = []

      while (true) {
        const { done, value } = await reader!.read()
        if (done) break

        const chunkText = new TextDecoder().decode(value, { stream: true })
        chunks.push(chunkText)

        // Process chunks to update progress (this part might need refinement based on API response format)
        try {
          const progressData = JSON.parse(chunkText)
          if (progressData.progress !== undefined) {
            setGeneratingVideoProgress(progressData.progress)
            console.log(`[v0] 영상 생성 진행률: ${progressData.progress}%`)
          }
          if (progressData.audioBase64) {
            receivedLength += progressData.audioBase64.length
          }
        } catch (e) {
          // Ignore if not a progress update JSON
        }
      }

      const fullResponseText = chunks.join("")
      const result = JSON.parse(fullResponseText) // Assume the final response is JSON

      console.log(`[v0] Base64 오디오 데이터 수신, 크기: ${Math.round(receivedLength / 1024)} KB`)

      // Base64를 Blob URL로 변환
      const binaryString = atob(result.audioBase64)
      const bytes = new Uint8Array(binaryString.length)
      for (let i = 0; i < binaryString.length; i++) {
        bytes[i] = binaryString.charCodeAt(i)
      }
      const blob = new Blob([bytes], { type: "audio/mpeg" }) // Use mpeg for compatibility
      const audioUrl = URL.createObjectURL(blob)

      console.log("[v0] Blob URL 생성 완료:", audioUrl)

      const audio = new Audio(audioUrl)
      await new Promise<void>((resolve, reject) => {
        audio.addEventListener("loadedmetadata", () => {
          const realDuration = audio.duration
          console.log(
            `[v0] 실제 오디오 길이: ${realDuration.toFixed(3)}초 (서버 계산: ${result.duration.toFixed(3)}초)`,
          )

          const scaleFactor = realDuration / result.duration
          console.log(`[v0] 자막 타이밍 스케일 팩터: ${scaleFactor.toFixed(3)}`)

          const scaledSubtitles = result.subtitles.map((s: any, index: number) => ({
            id: index + 1,
            text: s.text,
            start: s.start * scaleFactor,
            end: s.end * scaleFactor,
          }))

          setVideoData({
            audioUrl,
            subtitles: scaledSubtitles,
            duration: realDuration,
          })

          setCompletedSteps((prev) => [...prev, "video"]) // Mark video step as completed
          resolve()
        })
        audio.addEventListener("error", reject)
      })

      console.log("[v0] 영상 생성 완료")
    } catch (error) {
      console.error("[v0] 영상 생성 실패:", error)
      alert(`영상 생성에 실패했습니다: ${error instanceof Error ? error.message : "알 수 없는 오류"}`)
    } finally {
      setIsGeneratingVideo(false)
      setGeneratingVideoProgress(0) // Reset progress
      setRenderingStatusMessage("")
    }
  }

