  // 음성만 내보내기 (각각)
  const handleExportIndividualAudios = async () => {
    if (!generatedAudios || generatedAudios.length === 0) {
      alert("개별 오디오 데이터가 없습니다.")
      return
    }

    try {
      // JSZip 인스턴스 생성
      const zip = new JSZip()
      
      // 각 오디오를 zip에 추가
      for (let i = 0; i < generatedAudios.length; i++) {
        try {
          const audio = generatedAudios[i]
          const response = await fetch(audio.audioUrl)
          const blob = await response.blob()
          
          // 확장자 추출 (URL에서 또는 blob type에서)
          let extension = 'mp3'
          const urlPath = audio.audioUrl.split('?')[0] // 쿼리 파라미터 제거
          const urlExtension = urlPath.split('.').pop()?.toLowerCase()
          if (urlExtension && ['mp3', 'wav', 'm4a', 'ogg', 'webm'].includes(urlExtension)) {
            extension = urlExtension
          } else if (blob.type) {
            const mimeExtension = blob.type.split('/')[1]
            if (mimeExtension && ['mpeg', 'wav', 'm4a', 'ogg', 'webm'].includes(mimeExtension)) {
              extension = mimeExtension === 'mpeg' ? 'mp3' : mimeExtension
            }
          }
          
          // zip에 오디오 추가
          const fileName = `음악${i + 1}.${extension}`
          zip.file(fileName, blob)
        } catch (error) {
          console.error(`오디오 ${i + 1} 로드 실패:`, error)
        }
      }
      
      // zip 파일 생성 및 다운로드
      const zipBlob = await zip.generateAsync({ type: "blob" })
      const zipUrl = URL.createObjectURL(zipBlob)
      const link = document.createElement('a')
      link.href = zipUrl
      link.download = `음성모음_${Date.now()}.zip`
      document.body.appendChild(link)
      link.click()
      document.body.removeChild(link)
      URL.revokeObjectURL(zipUrl)
      
      console.log(`[음성 내보내기] ${generatedAudios.length}개의 음성을 zip 파일로 다운로드 완료`)
    } catch (error) {
      console.error("[음성 내보내기] zip 파일 생성 실패:", error)
      alert("음성을 zip 파일로 묶는 중 오류가 발생했습니다.")
    }
  }

  const handleSaveThumbnailImage = async () => {
    if (!thumbnailPreviewRef.current) {
      alert("썸네일 미리보기를 찾을 수 없습니다.")
      return
    }

    try {
      // html2canvas-pro를 사용하여 실제 미리보기 div를 캡처 (oklch 색상 지원)
      const html2canvasModule = await import("html2canvas-pro")
      const html2canvas = html2canvasModule.default || html2canvasModule
      
      if (typeof html2canvas !== 'function') {
        throw new Error("html2canvas-pro를 불러올 수 없습니다.")
      }
      
      const element = thumbnailPreviewRef.current
      
      // 원본 요소를 직접 사용 (html2canvas-pro가 oklch를 지원하므로 원본 사용 가능)
      // 이미지가 로드될 때까지 기다리기
      // 이미지가 로드될 때까지 기다리기
      const images = element.querySelectorAll('img')
      const imagePromises = Array.from(images).map((img) => {
        if (img.complete && img.naturalWidth > 0) {
          return Promise.resolve()
        }
        return new Promise<void>((resolve) => {
          const timeout = setTimeout(() => resolve(), 5000) // 5초 타임아웃
          img.onload = () => {
            clearTimeout(timeout)
            resolve()
          }
          img.onerror = () => {
            clearTimeout(timeout)
            resolve() // 에러가 나도 계속 진행
          }
        })
      })
      
      await Promise.all(imagePromises)
      
      // html2canvas-pro는 oklch를 지원하므로 복잡한 변환 로직 불필요
      // 실제 미리보기 크기 그대로 유지 (640x360)
      const canvas = await html2canvas(element, {
        width: element.offsetWidth || 640,
        height: element.offsetHeight || 360,
        scale: 1, // 실제 크기 그대로 저장
        backgroundColor: "#000000",
        useCORS: true,
        allowTaint: true,
        logging: false,
      })

      // Canvas가 제대로 생성되었는지 확인
      if (!canvas || !(canvas instanceof HTMLCanvasElement)) {
        throw new Error("캔버스 생성에 실패했습니다.")
      }

      // Canvas를 이미지로 변환하여 다운로드
      // toBlob을 Promise로 변환하여 안전하게 처리
      const blob = await new Promise<Blob | null>((resolve, reject) => {
        if (!canvas || typeof canvas.toBlob !== 'function') {
          reject(new Error("캔버스의 toBlob 메서드를 사용할 수 없습니다."))
          return
        }
        try {
          canvas.toBlob(
            (blob) => {
              if (blob) {
                resolve(blob)
              } else {
                reject(new Error("Blob 생성에 실패했습니다."))
              }
            },
            "image/jpeg",
            0.95,
          )
        } catch (error) {
          reject(error)
        }
      })
      
      if (blob) {
        const url = URL.createObjectURL(blob)
        const a = document.createElement("a")
        a.href = url
        a.download = `thumbnail-${Date.now()}.jpg`
        document.body.appendChild(a)
        a.click()
        document.body.removeChild(a)
        URL.revokeObjectURL(url)
      } else {
        alert("이미지 저장에 실패했습니다.")
      }
    } catch (error) {
      console.error("썸네일 저장 오류:", error)
      alert(`썸네일 저장에 실패했습니다: ${error instanceof Error ? error.message : "알 수 없는 오류"}`)
    }
  }

  const handleImageMouseDown = (e: React.MouseEvent) => {
    e.preventDefault()
    e.stopPropagation()
    setIsDraggingImage(true)
    setSelectedImageElement(true)
    setSelectedTextIndex(null) // 이미지 선택 시 텍스트 선택 해제
  }

  const handleImageMouseMove = (e: React.MouseEvent) => {
    if (!isDraggingImage) return

    const rect = e.currentTarget.getBoundingClientRect()
    const x = ((e.clientX - rect.left) / rect.width) * 100
    const y = ((e.clientY - rect.top) / rect.height) * 100

    // 오버레이 이미지가 선택된 경우
    if (thumbnailOverlayImage && selectedImageElement) {
      setOverlayImagePosition({
        x: Math.max(0, Math.min(100, x)),
        y: Math.max(0, Math.min(100, y)),
      })
    } else if (generatedImage) {
      // 인물 이미지가 선택된 경우
      setDoctorImagePosition({
        x: Math.max(0, Math.min(100, x)),
        y: Math.max(0, Math.min(100, y)),
      })
    }
  }

