                            const sceneNumber = Number.parseInt(idParts[1] || "0")
                            const imageNumber = Number.parseInt(idParts[3] || "0")
                            sceneVideoKey = `${sceneNumber}-${imageNumber}`
                            hasVideo = convertedSceneVideos.has(sceneVideoKey)
